// models/Block.ts
import { Schema, model, Types } from 'mongoose';
const BlockSchema = new Schema({
  _id: { type: String }, // ULID
  docId: { type: String, required: true, index: true },
  parentId: { type: String, default: null },
  order: { type: Number, required: true },
  version: { type: Number, default: 0 },
  content: { type: Schema.Types.Mixed },
  deletedAt: { type: Date, default: null },
}, { discriminatorKey: 'kind', timestamps: true });
export const Block = model('Block', BlockSchema);
Block.discriminator('paragraph', new Schema({ text: String, marks: [Object] }));
Block.discriminator('heading', new Schema({ text: String, level: Number }));
Block.discriminator('code', new Schema({ text: String, lang: String }));

// models/Op.ts
const OpSchema = new Schema({
  docId: { type: String, required: true },
  blockId: { type: String, required: true },
  serverSeq: { type: Number, required: true },
  clientId: { type: String, required: true },
  clientSeq: { type: Number, required: true },
  parentVersion: { type: Number, required: true },
  type: { type: String, enum: ['insert','delete','update','move'] },
  payload: Schema.Types.Mixed,
  authorId: String,
  createdAt: { type: Date, default: Date.now, expires: '90d' },
});
OpSchema.index({ docId: 1, serverSeq: 1 });
OpSchema.index({ docId: 1, clientId: 1, clientSeq: 1 }, { unique: true });

