// src/socket/docs.namespace.ts
import { Namespace, Socket } from 'socket.io';
import { z } from 'zod';
import mongoose from 'mongoose';
import { Block } from '../models/Block';
import { Op } from '../models/Op';
import { redis } from '../infra/redis';
import { logger } from '../infra/logger';
import { metrics } from '../infra/metrics';

const ClientOpSchema = z.object({
  docId: z.string().min(1).max(64),
  blockId: z.string().min(1).max(64),
  clientId: z.string().uuid(),
  clientSeq: z.number().int().nonnegative(),
  parentVersion: z.number().int().nonnegative(),
  type: z.enum(['insert','delete','update','move']),
  payload: z.unknown(),
});

export function registerDocsNamespace(nsp: Namespace) {
  nsp.use(async (socket, next) => {
    try {
      const token = socket.handshake.auth?.token;
      const user = await verifyJwt(token); // throws on invalid
      (socket.data as any).user = user;
      next();
    } catch (e) { next(new Error('unauthorized')); }
  });

  nsp.use(async (socket, next) => {
    const key = `rl:ops:${socket.data.user.id}`;
    const count = await redis.incr(key);
    if (count === 1) await redis.expire(key, 1);
    if (count > 200) return next(new Error('rate_limited'));
    next();
  });

  nsp.on('connection', (socket: Socket) => {
    socket.on('doc:open', async ({ docId }, ack) => {
      const allowed = await canRead(socket.data.user.id, docId);
      if (!allowed) return ack({ error: 'forbidden' });
      await socket.join(`doc:${docId}`);
      const blocks = await Block.find({ docId, deletedAt: null }).sort({ order: 1 }).lean();
      const headSeq = await Op.findOne({ docId }).sort({ serverSeq: -1 }).select('serverSeq').lean();
      ack({ blocks, headSeq: headSeq?.serverSeq ?? 0 });
    });

    socket.on('doc:sync', async ({ docId, lastServerSeq }, ack) => {
      const missed = await Op.find({ docId, serverSeq: { $gt: lastServerSeq } }).sort({ serverSeq: 1 }).limit(2000).lean();
      ack({ ops: missed });
    });

    socket.on('op:submit', async (raw, ack) => {
      const t0 = Date.now();
      const parsed = ClientOpSchema.safeParse(raw);
      if (!parsed.success) return ack({ error: 'bad_op' });
      const op = parsed.data;
      const session = await mongoose.startSession();
      try {
        let serverSeq: number | null = null;
        await session.withTransaction(async () => {
          try {
            const counter = await mongoose.connection.db.collection('counters').findOneAndUpdate(
              { _id: `doc:${op.docId}` as any }, { $inc: { seq: 1 } }, { upsert: true, returnDocument: 'after', session },
            );
            serverSeq = counter!.seq;
            await Op.create([{ ...op, serverSeq, authorId: socket.data.user.id }], { session });
          } catch (e: any) {
            if (e.code === 11000) { serverSeq = -1; return; } // idempotent
            throw e;
          }
          const updated = await Block.findOneAndUpdate(
            { _id: op.blockId, version: op.parentVersion },
            applyOpToUpdate(op), { new: true, session, upsert: op.type === 'insert' },
          );
          if (!updated && op.type !== 'insert') throw new Error('version_conflict');
        }, { readConcern: { level: 'majority' }, writeConcern: { w: 'majority', j: true } });
        if (serverSeq === -1) return ack({ duplicate: true });
        socket.to(`doc:${op.docId}`).emit('op:apply', { ...op, serverSeq, authorId: socket.data.user.id, serverTs: Date.now() });
        ack({ serverSeq });
        metrics.histogram('op_latency_ms', Date.now() - t0);
      } catch (e: any) {
        if (e.message === 'version_conflict') {
          const head = await Block.findById(op.blockId).lean();
          return ack({ conflict: true, head });
        }
        logger.error({ err: e, op }, 'op_failed');
        ack({ error: 'server_error' });
      } finally { await session.endSession(); }
    });

    socket.on('disconnect', () => { metrics.gauge('docs_sockets', nsp.sockets.size); });
  });
}

function applyOpToUpdate(op: any) {
  const inc = { $inc: { version: 1 } };
  if (op.type === 'update') return { ...inc, $set: { content: op.payload } };
  if (op.type === 'delete') return { ...inc, $set: { deletedAt: new Date() } };
  if (op.type === 'move')   return { ...inc, $set: { order: op.payload.order, parentId: op.payload.parentId } };
  return { ...inc, $set: { content: op.payload, order: op.payload.order } };
}

