// src/socket/socketSingleton.ts
import { io, Socket } from 'socket.io-client';
let docsSocket: Socket | null = null;
export function getDocsSocket(token: string): Socket {
  if (docsSocket) return docsSocket;
  docsSocket = io('/docs', { auth: { token }, transports: ['websocket'], reconnection: true, reconnectionDelayMax: 5000 });
  return docsSocket;
}
export function disposeDocsSocket() { docsSocket?.disconnect(); docsSocket = null; }

// src/hooks/useCollaborativeDoc.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { getDocsSocket } from '../socket/socketSingleton';
import { ulid } from 'ulid';

type Block = { _id: string; version: number; content: any; order: number; kind: string };
type LocalOp = { clientSeq: number; op: any; resolve: (s:number)=>void; reject:(e:Error)=>void };

export function useCollaborativeDoc(docId: string, token: string) {
  const [blocks, setBlocks] = useState<Block[]>([]);
  const [connected, setConnected] = useState(false);
  const lastServerSeqRef = useRef(0);
  const clientIdRef = useRef(ulid());
  const clientSeqRef = useRef(0);
  const pendingRef = useRef<Map<number, LocalOp>>(new Map());
  const blocksRef = useRef<Block[]>([]);
  blocksRef.current = blocks;

  useEffect(() => {
    const socket = getDocsSocket(token);
    const onConnect = () => {
      setConnected(true);
      if (lastServerSeqRef.current === 0) {
        socket.emit('doc:open', { docId }, (res: any) => {
          if (res.error) return;
          setBlocks(res.blocks);
          lastServerSeqRef.current = res.headSeq;
        });
      } else {
        socket.emit('doc:sync', { docId, lastServerSeq: lastServerSeqRef.current }, (res: any) => {
          for (const op of res.ops) applyRemoteOp(op);
        });
      }
    };
    const onDisconnect = () => setConnected(false);
    const onOpApply = (op: any) => {
      if (op.clientId === clientIdRef.current) return;
      applyRemoteOp(op);
    };
    const applyRemoteOp = (op: any) => {
      lastServerSeqRef.current = Math.max(lastServerSeqRef.current, op.serverSeq);
      setBlocks(prev => mergeOp(prev, op));
    };
    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.on('op:apply', onOpApply);
    if (socket.connected) onConnect();
    return () => {
      socket.emit('doc:close', { docId });
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.off('op:apply', onOpApply);
    };
  }, [docId, token]);

  const submitOp = useCallback((blockId: string, type: string, payload: any): Promise<number> => {
    const socket = getDocsSocket(token);
    const block = blocksRef.current.find(b => b._id === blockId);
    const clientSeq = ++clientSeqRef.current;
    const op = { docId, blockId, clientId: clientIdRef.current, clientSeq, parentVersion: block?.version ?? 0, type, payload };
    setBlocks(prev => mergeOp(prev, { ...op, serverSeq: -1, optimistic: true }));
    return new Promise((resolve, reject) => {
      pendingRef.current.set(clientSeq, { clientSeq, op, resolve, reject });
      const timer = setTimeout(() => { pendingRef.current.delete(clientSeq); reject(new Error('timeout')); }, 10000);
      socket.emit('op:submit', op, (res: any) => {
        clearTimeout(timer);
        pendingRef.current.delete(clientSeq);
        if (res?.error) reject(new Error(res.error));
        else if (res?.conflict) { setBlocks(prev => prev.map(b => b._id === blockId ? res.head : b)); reject(new Error('conflict')); }
        else resolve(res.serverSeq);
      });
    });
  }, [docId, token]);

  return { blocks, connected, submitOp };
}

function mergeOp(blocks: Block[], op: any): Block[] {
  if (op.type === 'delete') return blocks.filter(b => b._id !== op.blockId);
  if (op.type === 'insert' && !blocks.find(b => b._id === op.blockId)) return [...blocks, { _id: op.blockId, version: 1, content: op.payload, order: op.payload.order, kind: op.payload.kind }].sort((a,b)=>a.order-b.order);
  return blocks.map(b => b._id === op.blockId ? { ...b, content: op.payload, version: op.serverSeq > 0 ? b.version + 1 : b.version } : b);
}

// src/components/DocEditor.tsx
import { useCollaborativeDoc } from '../hooks/useCollaborativeDoc';
export function DocEditor({ docId, token }: { docId: string; token: string }) {
  const { blocks, connected, submitOp } = useCollaborativeDoc(docId, token);
  return (<div>{!connected && <div role="status">reconnecting…</div>}{blocks.map(b => (<div key={b._id} contentEditable suppressContentEditableWarning onBlur={(e)=>submitOp(b._id,'update',{ text:e.currentTarget.textContent }).catch(()=>{})}>{b.content?.text}</div>))}</div>);
}

