CREATE TABLE messages (
  id BIGSERIAL PRIMARY KEY,
  channel_id BIGINT NOT NULL,
  author_id BIGINT NOT NULL,
  client_msg_id UUID NOT NULL,
  body TEXT NOT NULL,
  reply_to_id BIGINT REFERENCES messages(id),
  version INT NOT NULL DEFAULT 1,
  edited_at TIMESTAMPTZ,
  deleted_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (channel_id, client_msg_id)
);
CREATE INDEX ON messages (channel_id, id DESC) WHERE deleted_at IS NULL;

CREATE TABLE messages_history (
  id BIGSERIAL PRIMARY KEY,
  message_id BIGINT NOT NULL REFERENCES messages(id),
  version INT NOT NULL,
  body TEXT NOT NULL,
  edited_by BIGINT NOT NULL,
  edited_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (message_id, version)
);

CREATE TABLE channel_reads (
  channel_id BIGINT NOT NULL,
  user_id BIGINT NOT NULL,
  last_read_msg_id BIGINT NOT NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (channel_id, user_id)
);

CREATE OR REPLACE FUNCTION snapshot_edit() RETURNS TRIGGER AS $$
BEGIN
  IF NEW.body IS DISTINCT FROM OLD.body THEN
    INSERT INTO messages_history(message_id, version, body, edited_by, edited_at)
    VALUES (OLD.id, OLD.version, OLD.body, NEW.author_id, now());
    NEW.version := OLD.version + 1;
    NEW.edited_at := now();
  END IF;
  RETURN NEW;
END; $$ LANGUAGE plpgsql;
CREATE TRIGGER messages_edit BEFORE UPDATE ON messages FOR EACH ROW EXECUTE FUNCTION snapshot_edit();

CREATE OR REPLACE FUNCTION notify_new_msg() RETURNS TRIGGER AS $$
BEGIN PERFORM pg_notify('chan_' || NEW.channel_id, NEW.id::text); RETURN NEW; END;
$$ LANGUAGE plpgsql;
CREATE TRIGGER messages_insert_notify AFTER INSERT ON messages FOR EACH ROW EXECUTE FUNCTION notify_new_msg();

