// src/notifier/pgListener.ts
import { Client } from 'pg';
import { redis } from '../infra/redis';
import { logger } from '../infra/logger';
const client = new Client({ connectionString: process.env.DATABASE_URL });
const activeChannels = new Set<string>();

export async function startListener() {
  await client.connect();
  client.on('notification', async (msg) => {
    if (!msg.channel.startsWith('chan_')) return;
    const channelId = msg.channel.slice(5);
    const msgId = msg.payload!;
    await redis.publish(`msg:chan:${channelId}`, msgId);
  });
  client.on('error', (e) => { logger.error({err:e},'pg_listener_error'); process.exit(1); }); // let supervisor restart
  setInterval(() => client.query('SELECT 1').catch(()=>process.exit(1)), 10_000); // detect silent drop
}
export async function subscribeChannel(channelId: string) {
  if (activeChannels.has(channelId)) return;
  await client.query(`LISTEN chan_${channelId}`);
  activeChannels.add(channelId);
}

// src/socket/chat.namespace.ts
import { Namespace, Socket } from 'socket.io';
import { pool } from '../infra/pg';
import { redis, sub } from '../infra/redis';
import { subscribeChannel } from '../notifier/pgListener';
import { z } from 'zod';

const typingRl = new Map<string, number>(); // userId → expiresAt

export function registerChatNamespace(nsp: Namespace) {
  nsp.use(authMw); nsp.use(tenantMw);

  sub.psubscribe('msg:chan:*');
  sub.on('pmessage', async (_pat, ch, msgId) => {
    const channelId = ch.split(':')[2];
    const { rows } = await pool.query('SELECT id,channel_id,author_id,body,version,created_at,edited_at FROM messages WHERE id=$1', [msgId]);
    if (rows[0]) nsp.to(`chan:${channelId}`).emit('msg:new', rowToMsg(rows[0]));
  });

  nsp.on('connection', (socket: Socket) => {
    socket.on('subscribe', async ({ channelId, sinceMsgId }, ack) => {
      const ok = await isMember(socket.data.user.id, channelId);
      if (!ok) return ack({ error: 'forbidden' });
      await socket.join(`chan:${channelId}`);
      await subscribeChannel(channelId);
      const { rows } = await pool.query(
        'SELECT id,channel_id,author_id,body,version,created_at,edited_at FROM messages WHERE channel_id=$1 AND id > $2 AND deleted_at IS NULL ORDER BY id ASC LIMIT 500',
        [channelId, sinceMsgId ?? 0],
      );
      ack({ messages: rows.map(rowToMsg) });
    });

    socket.on('typing:start', async ({ channelId }) => {
      const uid = socket.data.user.id;
      const key = `${uid}:${channelId}`;
      const now = Date.now();
      if ((typingRl.get(key) ?? 0) > now) return;
      typingRl.set(key, now + 3000);
      socket.to(`chan:${channelId}:typing`).emit('typing:active', { channelId, userId: uid, expiresAt: now + 4000 });
    });

    socket.on('read:update', async ({ channelId, lastReadMsgId }) => {
      await pool.query(
        `INSERT INTO channel_reads(channel_id,user_id,last_read_msg_id) VALUES ($1,$2,$3)
         ON CONFLICT (channel_id,user_id) DO UPDATE SET last_read_msg_id = GREATEST(channel_reads.last_read_msg_id, EXCLUDED.last_read_msg_id), updated_at = now()`,
        [channelId, socket.data.user.id, lastReadMsgId],
      );
    });
  });
}
function rowToMsg(r:any){ return { id:String(r.id), channelId:String(r.channel_id), authorId:String(r.author_id), body:r.body, version:r.version, createdAt:r.created_at, editedAt:r.edited_at }; }

// src/routes/messages.ts
import { Router } from 'express';
import { pool } from '../infra/pg';
export const messagesRouter = Router();
messagesRouter.post('/messages', async (req, res) => {
  const { channelId, clientMsgId, body, replyToId } = req.body;
  const userId = req.user!.id;
  const { rows } = await pool.query(
    `INSERT INTO messages(channel_id,author_id,client_msg_id,body,reply_to_id) VALUES ($1,$2,$3,$4,$5)
     ON CONFLICT (channel_id,client_msg_id) DO UPDATE SET body = messages.body RETURNING id, version, created_at`,
    [channelId, userId, clientMsgId, body, replyToId ?? null],
  );
  res.json({ id: String(rows[0].id), version: rows[0].version, createdAt: rows[0].created_at });
});
messagesRouter.patch('/messages/:id', async (req, res) => {
  const id = req.params.id; const { body, expectedVersion } = req.body;
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('SELECT pg_advisory_xact_lock(hashtext($1))', [`msg:${id}`]);
    const upd = await client.query('UPDATE messages SET body=$1 WHERE id=$2 AND version=$3 AND author_id=$4 AND deleted_at IS NULL RETURNING id,version,edited_at', [body, id, expectedVersion, req.user!.id]);
    if (upd.rowCount === 0) { await client.query('ROLLBACK'); return res.status(409).json({ error: 'conflict' }); }
    await client.query('COMMIT');
    // Edit fan-out goes via separate NOTIFY trigger we add similarly; omitted for brevity
    res.json(upd.rows[0]);
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
});

