// src/socket/chatSocket.ts
import { io, Socket } from 'socket.io-client';
let s: Socket | null = null;
export function getChatSocket(token:string){ if(s) return s; s = io('/chat', { auth:{token}, transports:['websocket'] }); return s; }

// src/hooks/useChannel.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { getChatSocket } from '../socket/chatSocket';
import { v4 as uuid } from 'uuid';

type Msg = { id:string; authorId:string; body:string; version:number; createdAt:string; editedAt?:string; pending?:boolean; clientMsgId?:string };
export function useChannel(channelId:string, token:string) {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [typing, setTyping] = useState<Set<string>>(new Set());
  const lastMsgIdRef = useRef<string>('0');
  const typingTimers = useRef(new Map<string, ReturnType<typeof setTimeout>>());
  const seenIds = useRef(new Set<string>());

  useEffect(() => {
    const socket = getChatSocket(token);
    const subscribe = () => socket.emit('subscribe', { channelId, sinceMsgId: lastMsgIdRef.current }, (res:any) => {
      if (res.error) return;
      for (const m of res.messages) ingest(m);
    });
    const ingest = (m:Msg) => {
      if (seenIds.current.has(m.id)) return; seenIds.current.add(m.id);
      lastMsgIdRef.current = m.id > lastMsgIdRef.current ? m.id : lastMsgIdRef.current;
      setMessages(prev => {
        const optimisticIdx = m.clientMsgId ? prev.findIndex(x => x.clientMsgId === m.clientMsgId && x.pending) : -1;
        if (optimisticIdx >= 0) { const next = [...prev]; next[optimisticIdx] = m; return next; }
        return [...prev, m];
      });
    };
    const onTyping = (e:{userId:string;expiresAt:number}) => {
      setTyping(prev => { const n = new Set(prev); n.add(e.userId); return n; });
      const prev = typingTimers.current.get(e.userId); if (prev) clearTimeout(prev);
      typingTimers.current.set(e.userId, setTimeout(() => setTyping(p => { const n = new Set(p); n.delete(e.userId); return n; }), e.expiresAt - Date.now()));
    };
    socket.on('connect', subscribe);
    socket.on('msg:new', ingest);
    socket.on('typing:active', onTyping);
    if (socket.connected) subscribe();
    return () => {
      socket.off('connect', subscribe); socket.off('msg:new', ingest); socket.off('typing:active', onTyping);
      typingTimers.current.forEach(clearTimeout); typingTimers.current.clear();
    };
  }, [channelId, token]);

  const send = useCallback(async (body:string) => {
    const clientMsgId = uuid();
    const optimistic:Msg = { id:`tmp_${clientMsgId}`, authorId:'me', body, version:1, createdAt:new Date().toISOString(), pending:true, clientMsgId };
    setMessages(p => [...p, optimistic]);
    try {
      const res = await fetch('/api/messages',{ method:'POST', headers:{'content-type':'application/json',authorization:`Bearer ${token}`}, body:JSON.stringify({channelId, clientMsgId, body}) });
      if (!res.ok) throw new Error('send_failed');
    } catch (e) {
      setMessages(p => p.map(m => m.clientMsgId === clientMsgId ? { ...m, pending:false, failed:true } as any : m));
    }
  }, [channelId, token]);

  const startTyping = useCallback(() => { getChatSocket(token).emit('typing:start', { channelId }); }, [channelId, token]);
  const markRead = useCallback((lastReadMsgId:string) => { getChatSocket(token).emit('read:update', { channelId, lastReadMsgId }); }, [channelId, token]);
  return { messages, typing, send, startTyping, markRead };
}

