// src/workers/rollupTailer.ts
import { Client as PG } from 'pg';
import mongoose from 'mongoose';
import { Rollup } from '../models/Rollup';
import { redis } from '../infra/redis';
import Redlock from 'redlock';
const lock = new Redlock([redis]);

export async function runTailer() {
  const lease = await lock.acquire(['lock:rollup-tailer'], 30_000);
  try {
    const pg = new PG({ connectionString: process.env.DATABASE_URL });
    await pg.connect();
    let processed = Number((await redis.get('rollup:lsn')) ?? 0);
    setInterval(async () => { try { await lease.extend(30_000); } catch { process.exit(1); } }, 10_000);
    while (true) {
      const { rows } = await pg.query('SELECT id, ts, amount_cents, sku_id, country, status FROM orders WHERE id > $1 ORDER BY id LIMIT 1000', [processed]);
      if (rows.length === 0) { await new Promise(r => setTimeout(r, 200)); continue; }
      const session = await mongoose.startSession();
      await session.withTransaction(async () => {
        for (const r of rows) {
          const bucket = new Date(Math.floor(new Date(r.ts).getTime()/60000)*60000);
          await Rollup.updateOne(
            { ts: bucket, 'dim.sku': String(r.sku_id), 'dim.country': r.country },
            { $inc: { revenueCents: r.amount_cents, orderCount: 1, errorCount: r.status==='error'?1:0 } },
            { upsert: true, session },
          );
        }
        processed = Number(rows[rows.length-1].id);
        await redis.set('rollup:lsn', String(processed));
      });
      await session.endSession();
      // Republish to socket fan-out
      await redis.publish('dash:tick', JSON.stringify(rows.map(r=>({ts:new Date(r.ts).getTime(),sku:String(r.sku_id),country:r.country,amount:Number(r.amount_cents),status:r.status}))));
    }
  } finally { try { await lease.release(); } catch {} }
}

// src/socket/dashboards.namespace.ts
import { Namespace, Socket } from 'socket.io';
import { sub } from '../infra/redis';
import { Rollup } from '../models/Rollup';

type Filter = { sku?: string[]; country?: string[]; minAmount?: number };
type Subscriber = { socket: Socket; dashId: string; filter: Filter; predicate: (e:any)=>boolean };

export function registerDashboardsNamespace(nsp: Namespace) {
  const subs = new Map<string, Subscriber>(); // socketId → subscriber
  nsp.use(authMw); nsp.use(orgMw);

  sub.subscribe('dash:tick');
  sub.on('message', (ch, payload) => {
    if (ch !== 'dash:tick') return;
    const events = JSON.parse(payload);
    for (const subr of subs.values()) {
      const filtered = events.filter(subr.predicate);
      if (filtered.length) subr.socket.emit('tick', { events: filtered });
    }
  });

  nsp.on('connection', (socket: Socket) => {
    socket.on('dash:subscribe', async ({ dashId, filter }, ack) => {
      const ok = await canRead(socket.data.user.id, dashId);
      if (!ok) return ack({ error: 'forbidden' });
      const validated = validateFilter(filter);
      if (!validated.ok) return ack({ error: validated.reason });
      await socket.join(`dash:${dashId}`);
      subs.set(socket.id, { socket, dashId, filter: validated.filter, predicate: compileFilter(validated.filter) });
      const snapshot = await Rollup.find({ ts: { $gte: new Date(Date.now()-15*60_000) } }).sort({ ts: 1 }).lean();
      ack({ snapshot: applyFilter(snapshot, validated.filter) });
    });

    socket.on('dash:filter', ({ filter }, ack) => {
      const cur = subs.get(socket.id); if (!cur) return ack({ error: 'not_subscribed' });
      const validated = validateFilter(filter);
      if (!validated.ok) return ack({ error: validated.reason });
      cur.filter = validated.filter; cur.predicate = compileFilter(validated.filter);
      ack({ ok: true });
    });

    socket.on('replay:request', async ({ t0, t1 }, ack) => {
      if (t1 - t0 > 24*3600_000) return ack({ error: 'window_too_large' });
      const cur = subs.get(socket.id); if (!cur) return ack({ error: 'not_subscribed' });
      const rows = await Rollup.find({ ts: { $gte: new Date(t0), $lte: new Date(t1) } }).sort({ ts: 1 }).lean();
      ack({ chunk: applyFilter(rows, cur.filter) });
    });

    socket.on('disconnect', () => subs.delete(socket.id));
  });
}

function compileFilter(f: Filter): (e:any)=>boolean {
  const skuSet = f.sku ? new Set(f.sku) : null;
  const cSet = f.country ? new Set(f.country) : null;
  const min = f.minAmount ?? 0;
  return (e) => (!skuSet || skuSet.has(e.sku)) && (!cSet || cSet.has(e.country)) && e.amount >= min;
}
function validateFilter(f: any): { ok: true; filter: Filter } | { ok: false; reason: string } {
  if (f.sku && f.sku.length > 50) return { ok: false, reason: 'too_many_skus' };
  return { ok: true, filter: f };
}
function applyFilter(rows:any[], f:Filter) { const p = compileFilter(f); return rows.filter(r => p({ sku: r.dim?.sku, country: r.dim?.country, amount: r.revenueCents })); }

