// src/hooks/useDashboard.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/dashboards',{auth:{token},transports:['websocket']}); return sock; }

type Tick = { ts:number; sku:string; country:string; amount:number; status:string };
export function useDashboard(dashId:string, token:string, initialFilter:any={}) {
  const [series, setSeries] = useState<Tick[]>([]);
  const [mode, setMode] = useState<'live'|'replay'>('live');
  const [connected, setConnected] = useState(false);
  const filterRef = useRef(initialFilter);
  const bufferRef = useRef<Tick[]>([]);
  const flushTimerRef = useRef<number | null>(null);

  useEffect(() => {
    const socket = getSock(token);
    const onConnect = () => {
      setConnected(true);
      socket.emit('dash:subscribe', { dashId, filter: filterRef.current }, (res:any) => {
        if (res.error) return;
        setSeries(res.snapshot.map((r:any)=>({ ts:new Date(r.ts).getTime(), sku:r.dim?.sku, country:r.dim?.country, amount:r.revenueCents, status:'ok' })));
      });
    };
    const onTick = ({ events }: { events: Tick[] }) => {
      if (mode !== 'live') return;
      bufferRef.current.push(...events);
      if (flushTimerRef.current == null) {
        flushTimerRef.current = window.setTimeout(() => {
          flushTimerRef.current = null;
          const drained = bufferRef.current; bufferRef.current = [];
          setSeries(prev => {
            const next = prev.concat(drained);
            const cutoff = Date.now() - 30*60_000;
            return next.filter(t => t.ts >= cutoff);
          });
        }, 100); // 10fps throttle for paint
      }
    };
    socket.on('connect', onConnect); socket.on('disconnect', () => setConnected(false)); socket.on('tick', onTick);
    if (socket.connected) onConnect();
    return () => {
      socket.off('connect', onConnect); socket.off('disconnect'); socket.off('tick', onTick);
      if (flushTimerRef.current) window.clearTimeout(flushTimerRef.current);
    };
  }, [dashId, token, mode]);

  const setFilter = useCallback((f:any) => {
    filterRef.current = f;
    getSock(token).emit('dash:filter', { filter: f }, (res:any) => { if (res.error) console.error(res.error); });
  }, [token]);

  const requestReplay = useCallback((t0:number, t1:number) => new Promise<Tick[]>((resolve, reject) => {
    getSock(token).emit('replay:request', { t0, t1 }, (res:any) => { if (res.error) reject(new Error(res.error)); else resolve(res.chunk.map((r:any)=>({ ts:new Date(r.ts).getTime(), sku:r.dim?.sku, country:r.dim?.country, amount:r.revenueCents, status:'ok' }))); });
  }), [token]);

  return { series, connected, mode, setMode, setFilter, requestReplay };
}

