import { useDashboard } from '../hooks/useDashboard';
import { useState } from 'react';
export function Dashboard({ dashId, token }:{dashId:string;token:string}) {
  const { series, connected, setFilter, setMode, requestReplay } = useDashboard(dashId, token);
  const [replayData, setReplayData] = useState<any[]>([]);
  return (<div>{!connected && <span>reconnecting…</span>}<button onClick={()=>setFilter({country:['US']})}>US only</button><button onClick={async()=>{setMode('replay');setReplayData(await requestReplay(Date.now()-3600_000,Date.now()));}}>Replay last hour</button><pre>{JSON.stringify({live:series.length,replay:replayData.length})}</pre></div>);
}

