// src/game/match.ts
import { Socket } from 'socket.io';
import { pool } from '../infra/pg';
import { encode } from '@msgpack/msgpack';

const TICK_HZ = 30;
const TICK_MS = 1000 / TICK_HZ;
const MAX_SPEED = 200; // px/sec
const INTEREST_RADIUS_SQ = 800 * 800;

type Entity = { id:string; userId:number; x:number; y:number; vx:number; vy:number; hp:number; type:'player'|'bullet'; lastInputSeq:number };
type PlayerSlot = { userId:number; socket: Socket | null; entity: Entity; pendingInputs: any[]; disconnectAt: number | null };

export class Match {
  tick = 0;
  entities = new Map<string, Entity>();
  players = new Map<number, PlayerSlot>();
  running = true;
  private snapshotTimer: NodeJS.Timeout;
  private tickTimer: NodeJS.Timeout;
  constructor(public matchId: number) {
    this.tickTimer = setInterval(() => this.runTick().catch(e => console.error('tick_err', e)), TICK_MS);
    this.snapshotTimer = setInterval(() => this.persistSnapshot().catch(e => console.error('snap_err', e)), 5000);
  }
  addPlayer(userId: number, socket: Socket, x = Math.random()*1000, y = Math.random()*1000) {
    const entity: Entity = { id: `p${userId}`, userId, x, y, vx:0, vy:0, hp:100, type:'player', lastInputSeq:0 };
    this.entities.set(entity.id, entity);
    this.players.set(userId, { userId, socket, entity, pendingInputs: [], disconnectAt: null });
  }
  handleInput(userId: number, input: any) {
    const slot = this.players.get(userId); if (!slot) return;
    if (input.seq <= slot.entity.lastInputSeq) return; // out-of-order or replay
    const mag = Math.hypot(input.mv[0], input.mv[1]);
    if (mag > 1.01) return; // anti-cheat: vector must be unit-or-less
    slot.pendingInputs.push(input);
  }
  detach(userId: number) {
    const slot = this.players.get(userId); if (!slot) return;
    slot.socket = null; slot.disconnectAt = Date.now();
  }
  reattach(userId: number, socket: Socket) {
    const slot = this.players.get(userId); if (!slot) return false;
    slot.socket = socket; slot.disconnectAt = null;
    return true;
  }
  private async runTick() {
    if (!this.running) return;
    this.tick++;
    const dt = TICK_MS / 1000;
    // process inputs
    for (const slot of this.players.values()) {
      const inputs = slot.pendingInputs; slot.pendingInputs = [];
      for (const inp of inputs) {
        slot.entity.vx = inp.mv[0] * MAX_SPEED;
        slot.entity.vy = inp.mv[1] * MAX_SPEED;
        slot.entity.lastInputSeq = inp.seq;
        if (inp.fire) { /* spawn bullet entity */ }
      }
      // detect disconnect timeout
      if (slot.disconnectAt && Date.now() - slot.disconnectAt > 30_000) {
        this.entities.delete(slot.entity.id); this.players.delete(slot.userId);
      }
    }
    // physics
    for (const e of this.entities.values()) { e.x += e.vx * dt; e.y += e.vy * dt; }
    // persist inputs for replay (batched)
    // (in practice: buffer + flush every 100 ticks)
    // fan-out per player with interest culling
    for (const slot of this.players.values()) {
      if (!slot.socket) continue;
      const visible: Entity[] = [];
      for (const other of this.entities.values()) {
        const dx = other.x - slot.entity.x, dy = other.y - slot.entity.y;
        if (dx*dx + dy*dy <= INTEREST_RADIUS_SQ) visible.push(other);
      }
      const snap = { tick: this.tick, ackedInputSeq: slot.entity.lastInputSeq, entities: visible.map(e => ({ id:e.id, x:Math.round(e.x), y:Math.round(e.y), hp:e.hp, type:e.type })) };
      slot.socket.volatile.emit('snapshot', snap); // volatile = drop if backpressured
    }
    if (this.players.size === 0) this.end().catch(()=>{});
  }
  private async persistSnapshot() {
    const state = encode({ tick: this.tick, entities: [...this.entities.values()] });
    await pool.query('INSERT INTO match_snapshots(match_id,tick,state) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING', [this.matchId, this.tick, state]);
    await pool.query('DELETE FROM match_snapshots WHERE match_id=$1 AND tick < $2', [this.matchId, this.tick - 600]); // keep 20s worth
  }
  async end() {
    this.running = false; clearInterval(this.tickTimer); clearInterval(this.snapshotTimer);
    await pool.query("UPDATE matches SET status='ended', ended_at=now() WHERE id=$1", [this.matchId]);
    for (const slot of this.players.values()) slot.socket?.emit('match:ended');
  }
}

// src/socket/game.namespace.ts
import { Namespace } from 'socket.io';
import { Match } from '../game/match';
import { pool } from '../infra/pg';
const matches = new Map<number, Match>();

export function registerGameNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.use(async (socket, next) => {
    const { matchId, reconnectToken } = socket.handshake.auth as any;
    const { rows } = await pool.query('SELECT user_id FROM match_players WHERE match_id=$1 AND user_id=$2 AND reconnect_token=$3', [matchId, socket.data.user.id, reconnectToken]);
    if (rows.length === 0) return next(new Error('forbidden'));
    (socket.data as any).matchId = Number(matchId);
    next();
  });
  nsp.on('connection', (socket) => {
    const matchId = socket.data.matchId as number;
    const userId = socket.data.user.id as number;
    let match = matches.get(matchId);
    if (!match) { match = new Match(matchId); matches.set(matchId, match); }
    if (!match.reattach(userId, socket)) match.addPlayer(userId, socket);
    socket.emit('match:joined', { tick: match.tick });
    socket.on('input', (input) => match!.handleInput(userId, input));
    socket.on('disconnect', () => match!.detach(userId));
  });
}

