// src/hooks/useMatch.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getGameSock(token:string, matchId:string, reconnectToken:string) {
  if (sock) return sock;
  sock = io('/game',{auth:{token,matchId,reconnectToken},transports:['websocket'],reconnection:true});
  return sock;
}

type Entity = { id:string; x:number; y:number; hp:number; type:string };
type Snapshot = { tick:number; ackedInputSeq:number; entities:Entity[] };
type LocalInput = { seq:number; clientTick:number; mv:[number,number]; fire?:boolean };

export function useMatch(token:string, matchId:string, reconnectToken:string) {
  const [renderEntities, setRenderEntities] = useState<Entity[]>([]);
  const stateRef = useRef<{ entities: Map<string,Entity>; serverTick: number }>({ entities: new Map(), serverTick: 0 });
  const inputsRef = useRef<LocalInput[]>([]);
  const seqRef = useRef(0);
  const moveRef = useRef<[number,number]>([0,0]);
  const meIdRef = useRef<string | null>(null);

  useEffect(() => {
    const socket = getGameSock(token, matchId, reconnectToken);
    const onSnapshot = (snap: Snapshot) => {
      // reconcile: take server state, re-apply unacknowledged local inputs
      const next = new Map<string, Entity>();
      for (const e of snap.entities) next.set(e.id, e);
      // discard acked inputs
      inputsRef.current = inputsRef.current.filter(i => i.seq > snap.ackedInputSeq);
      // predict forward: apply pending inputs to our own entity
      const me = meIdRef.current && next.get(meIdRef.current);
      if (me) {
        for (const i of inputsRef.current) { me.x += i.mv[0] * 200 * (1/30); me.y += i.mv[1] * 200 * (1/30); }
      }
      stateRef.current = { entities: next, serverTick: snap.tick };
      // smooth-blend rather than snap: simple lerp toward target
      setRenderEntities(prev => {
        const targetMap = next;
        return [...targetMap.values()].map(t => {
          const cur = prev.find(p => p.id === t.id);
          if (!cur) return t;
          return { ...t, x: cur.x + (t.x - cur.x) * 0.3, y: cur.y + (t.y - cur.y) * 0.3 };
        });
      });
    };
    const onJoined = ({ tick }: { tick: number }) => { stateRef.current.serverTick = tick; meIdRef.current = `p${(JSON.parse(atob(token.split('.')[1])).sub)}`; };
    socket.on('snapshot', onSnapshot);
    socket.on('match:joined', onJoined);
    // input loop @ 60Hz
    const inputTimer = window.setInterval(() => {
      seqRef.current++;
      const input: LocalInput = { seq: seqRef.current, clientTick: stateRef.current.serverTick, mv: moveRef.current };
      inputsRef.current.push(input);
      if (inputsRef.current.length > 120) inputsRef.current.splice(0, inputsRef.current.length - 120); // safety cap
      socket.emit('input', input);
    }, 1000/60);
    // keyboard
    const keys = { w:0, a:0, s:0, d:0 } as Record<string,number>;
    const updateMv = () => { moveRef.current = [keys.d - keys.a, keys.s - keys.w]; };
    const kd = (e:KeyboardEvent) => { if (e.key in keys) { keys[e.key] = 1; updateMv(); } };
    const ku = (e:KeyboardEvent) => { if (e.key in keys) { keys[e.key] = 0; updateMv(); } };
    window.addEventListener('keydown', kd); window.addEventListener('keyup', ku);
    return () => {
      socket.off('snapshot', onSnapshot); socket.off('match:joined', onJoined);
      window.clearInterval(inputTimer);
      window.removeEventListener('keydown', kd); window.removeEventListener('keyup', ku);
    };
  }, [token, matchId, reconnectToken]);

  return { entities: renderEntities };
}

