CREATE TABLE lots (
  id BIGSERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  starts_at TIMESTAMPTZ NOT NULL,
  ends_at TIMESTAMPTZ NOT NULL,
  reserve_cents BIGINT NOT NULL,
  current_bid_cents BIGINT NOT NULL DEFAULT 0,
  current_bidder_id BIGINT,
  bid_count INT NOT NULL DEFAULT 0,
  status TEXT NOT NULL CHECK (status IN ('upcoming','live','closed'))
);

CREATE TABLE bids (
  id BIGSERIAL PRIMARY KEY,
  lot_id BIGINT NOT NULL REFERENCES lots(id),
  bidder_id BIGINT NOT NULL,
  amount_cents BIGINT NOT NULL,
  client_nonce UUID NOT NULL,
  signature TEXT NOT NULL,
  status TEXT NOT NULL CHECK (status IN ('accepted','rejected')),
  reject_reason TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (lot_id, bidder_id, client_nonce)
);
CREATE INDEX ON bids (lot_id, created_at DESC);

CREATE TABLE audit_log (
  id BIGSERIAL PRIMARY KEY,
  lot_id BIGINT NOT NULL,
  event_type TEXT NOT NULL,
  payload JSONB NOT NULL,
  prev_hash BYTEA NOT NULL,
  row_hash BYTEA NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX ON audit_log (lot_id, id);

CREATE OR REPLACE FUNCTION append_audit(p_lot BIGINT, p_type TEXT, p_payload JSONB) RETURNS VOID AS $$
DECLARE prev BYTEA; new_hash BYTEA;
BEGIN
  SELECT row_hash INTO prev FROM audit_log WHERE lot_id=p_lot ORDER BY id DESC LIMIT 1 FOR UPDATE;
  prev := COALESCE(prev, decode('00','hex'));
  new_hash := digest(prev || convert_to(p_payload::text,'UTF8'),'sha256');
  INSERT INTO audit_log(lot_id,event_type,payload,prev_hash,row_hash) VALUES (p_lot,p_type,p_payload,prev,new_hash);
END; $$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION notify_lot() RETURNS TRIGGER AS $$ BEGIN PERFORM pg_notify('lot_'||NEW.id, json_build_object('current_bid',NEW.current_bid_cents,'bidder',NEW.current_bidder_id)::text); RETURN NEW; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER lots_notify AFTER UPDATE OF current_bid_cents ON lots FOR EACH ROW EXECUTE FUNCTION notify_lot();

