// src/routes/bids.ts
import { Router } from 'express';
import { pool } from '../infra/pg';
import { verifyBidSignature } from '../infra/signing';
import { metrics } from '../infra/metrics';
export const bidsRouter = Router();
bidsRouter.post('/bids', async (req, res) => {
  const { lotId, amountCents, clientNonce, signature } = req.body;
  const userId = req.user!.id;
  if (!verifyBidSignature({ lotId, amountCents, clientNonce, userId }, signature)) {
    return res.status(400).json({ error: 'invalid_signature' });
  }
  const t0 = Date.now();
  const client = await pool.connect();
  try {
    await client.query('BEGIN ISOLATION LEVEL REPEATABLE READ');
    await client.query('SELECT pg_advisory_xact_lock($1)', [lotId]);
    const lotRes = await client.query('SELECT current_bid_cents, ends_at, status FROM lots WHERE id=$1 FOR UPDATE', [lotId]);
    if (lotRes.rowCount === 0) { await client.query('ROLLBACK'); return res.status(404).json({ error: 'no_lot' }); }
    const lot = lotRes.rows[0];
    if (lot.status !== 'live' || new Date(lot.ends_at).getTime() < Date.now()) {
      await client.query(`SELECT append_audit($1,'bid_rejected',$2::jsonb)`, [lotId, JSON.stringify({userId,amountCents,reason:'closed'})]);
      await client.query('INSERT INTO bids(lot_id,bidder_id,amount_cents,client_nonce,signature,status,reject_reason) VALUES ($1,$2,$3,$4,$5,$6,$7) ON CONFLICT DO NOTHING', [lotId,userId,amountCents,clientNonce,signature,'rejected','closed']);
      await client.query('COMMIT');
      return res.status(409).json({ error: 'closed' });
    }
    const minIncrement = 100; // $1 in cents
    if (amountCents < lot.current_bid_cents + minIncrement) {
      await client.query(`SELECT append_audit($1,'bid_rejected',$2::jsonb)`, [lotId, JSON.stringify({userId,amountCents,reason:'too_low'})]);
      await client.query('INSERT INTO bids(lot_id,bidder_id,amount_cents,client_nonce,signature,status,reject_reason) VALUES ($1,$2,$3,$4,$5,$6,$7) ON CONFLICT DO NOTHING', [lotId,userId,amountCents,clientNonce,signature,'rejected','too_low']);
      await client.query('COMMIT');
      return res.status(409).json({ error: 'too_low', currentBidCents: Number(lot.current_bid_cents) });
    }
    let bidInsert;
    try {
      bidInsert = await client.query('INSERT INTO bids(lot_id,bidder_id,amount_cents,client_nonce,signature,status) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id', [lotId,userId,amountCents,clientNonce,signature,'accepted']);
    } catch (e: any) {
      if (e.code === '23505') { // unique violation = replay
        await client.query('COMMIT');
        const existing = await pool.query('SELECT id,status FROM bids WHERE lot_id=$1 AND bidder_id=$2 AND client_nonce=$3', [lotId,userId,clientNonce]);
        return res.json({ id: existing.rows[0].id, idempotent: true, status: existing.rows[0].status });
      }
      throw e;
    }
    await client.query('UPDATE lots SET current_bid_cents=$1, current_bidder_id=$2, bid_count=bid_count+1 WHERE id=$3', [amountCents,userId,lotId]);
    await client.query(`SELECT append_audit($1,'bid_accepted',$2::jsonb)`, [lotId, JSON.stringify({bidId:bidInsert.rows[0].id,userId,amountCents,ts:Date.now()})]);
    await client.query('COMMIT');
    metrics.histogram('bid_accept_ms', Date.now() - t0);
    res.json({ id: bidInsert.rows[0].id, status: 'accepted' });
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
});

// src/notifier/lotListener.ts
import { Client } from 'pg'; import { redis } from '../infra/redis';
const c = new Client({ connectionString: process.env.DATABASE_URL });
export async function startLotListener(activeLotIds: string[]) {
  await c.connect();
  for (const id of activeLotIds) await c.query(`LISTEN lot_${id}`);
  c.on('notification', async (n) => {
    if (!n.channel.startsWith('lot_')) return;
    const lotId = n.channel.slice(4);
    await redis.publish(`auction:lot:${lotId}`, n.payload!);
  });
}

