import { Namespace } from 'socket.io';
import { sub } from '../infra/redis';
export function registerAuctionNamespace(nsp: Namespace) {
  nsp.use(authMw); nsp.use(kycMw);
  sub.psubscribe('auction:lot:*');
  sub.on('pmessage', (_p, ch, payload) => {
    const lotId = ch.split(':')[2];
    const data = JSON.parse(payload);
    nsp.to(`lot:${lotId}`).emit('bid:update', { lotId, currentBidCents: data.current_bid, currentBidderId: String(data.bidder), ts: Date.now() });
  });
