// src/hooks/useLotBidding.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
import { v4 as uuid } from 'uuid';
let sock: Socket | null = null;
function getAuctionSock(token:string){ if(sock) return sock; sock = io('/auction',{auth:{token},transports:['websocket']}); return sock; }

type LotState = { currentBidCents:number; currentBidderId:string|null; isMyLead:boolean };
type Pending = { nonce:string; amountCents:number; rolledBack?:boolean };

export function useLotBidding(lotId:string, token:string, myUserId:string) {
  const [state, setState] = useState<LotState>({ currentBidCents:0, currentBidderId:null, isMyLead:false });
  const [pending, setPending] = useState<Pending[]>([]);
  const [connected, setConnected] = useState(false);
  const seenNonces = useRef(new Set<string>());

  useEffect(() => {
    const socket = getAuctionSock(token);
    const onConnect = () => { setConnected(true); socket.emit('lot:watch', { lotId }, () => {}); fetch(`/api/lots/${lotId}`).then(r=>r.json()).then((lot:any)=>setState({currentBidCents:Number(lot.currentBidCents),currentBidderId:lot.currentBidderId,isMyLead:lot.currentBidderId===myUserId})); };
    const onUpdate = (u: { lotId:string; currentBidCents:number; currentBidderId:string }) => {
      if (u.lotId !== lotId) return;
      setState({ currentBidCents: u.currentBidCents, currentBidderId: u.currentBidderId, isMyLead: u.currentBidderId === myUserId });
      // remove pending bids that were eclipsed
      setPending(prev => prev.map(p => p.amountCents <= u.currentBidCents && u.currentBidderId !== myUserId ? { ...p, rolledBack: true } : p).filter(p => !p.rolledBack || Date.now() - 0 < 2000));
    };
    socket.on('connect', onConnect); socket.on('disconnect', () => setConnected(false)); socket.on('bid:update', onUpdate);
    if (socket.connected) onConnect();
    return () => { socket.off('connect', onConnect); socket.off('disconnect'); socket.off('bid:update', onUpdate); };
  }, [lotId, token, myUserId]);

  const placeBid = useCallback(async (amountCents:number) => {
    const nonce = uuid();
    if (seenNonces.current.has(nonce)) return; seenNonces.current.add(nonce);
    setPending(p => [...p, { nonce, amountCents }]);
    // sign client-side using user's session key (omitted: details depend on auth flow)
    const signature = await signBid({ lotId, amountCents, clientNonce: nonce, userId: myUserId });
    try {
      const res = await fetch('/api/bids',{ method:'POST', headers:{'content-type':'application/json',authorization:`Bearer ${token}`}, body: JSON.stringify({ lotId, amountCents, clientNonce: nonce, signature }) });
      const body = await res.json();
      if (!res.ok) {
        setPending(p => p.map(x => x.nonce === nonce ? { ...x, rolledBack: true } : x));
        return { ok: false, reason: body.error, currentBidCents: body.currentBidCents };
      }
      // accepted — pending stays until bid:update echoes (then resolves on isMyLead)
      return { ok: true };
    } catch (e) {
      // network error: keep pending; on reconnect retry with same nonce
      return { ok: false, reason: 'network' };
    }
  }, [lotId, token, myUserId]);

  return { state, pending, connected, placeBid };
}

async function signBid(b:any){ /* user holds session signing key in IndexedDB; HMAC */ return 'sig'; }

