// src/socket/presence.namespace.ts
import { Namespace } from 'socket.io';
import { redis, sub } from '../infra/redis';
import { Workspace } from '../models/Workspace';
import { logger } from '../infra/logger';

const DEVICE_TTL_S = 60;
const GRACE_MS = 30_000;
const pendingOffline = new Map<string, NodeJS.Timeout>();

export function registerPresenceNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.use((socket, next) => {
    const deviceId = socket.handshake.headers['x-device-id'];
    if (typeof deviceId !== 'string') return next(new Error('no_device'));
    (socket.data as any).deviceId = deviceId;
    next();
  });

  sub.subscribe('presence:change');
  sub.on('message', async (ch, payload) => {
    if (ch !== 'presence:change') return;
    const { userId, status, lastSeen, idleSince } = JSON.parse(payload);
    // find workspaces that contain userId AND that this node has any socket in
    const wss = await Workspace.find({ memberIds: userId }, { _id: 1 }).lean();
    for (const ws of wss) {
      const room = `ws:${ws._id}`;
      if (nsp.adapter.rooms.has(room)) {
        nsp.to(room).emit('presence:change', { userId, status, lastSeen, idleSince });
      }
    }
  });

  nsp.on('connection', async (socket) => {
    const userId = socket.data.user.id;
    const deviceId = socket.data.deviceId;
    const cancel = pendingOffline.get(userId);
    if (cancel) { clearTimeout(cancel); pendingOffline.delete(userId); }

    await touchPresence(userId, deviceId, 'online');
    await redis.publish('presence:change', JSON.stringify({ userId, status: 'online', lastSeen: Date.now() }));

    socket.on('ws:subscribe', async ({ workspaceIds }, ack) => {
      const wss = await Workspace.find({ _id: { $in: workspaceIds }, memberIds: userId }, { _id:1, memberIds:1 }).lean();
      const roster: any[] = [];
      for (const ws of wss) {
        await socket.join(`ws:${ws._id}`);
        const pipeline = redis.pipeline();
        for (const mid of ws.memberIds) pipeline.hgetall(`presence:${mid}`);
        const results = await pipeline.exec();
        results?.forEach(([, val]: any, i) => {
          const mid = ws.memberIds[i];
          if (val && Object.keys(val).length) {
            const devices = Object.values(val).map((s:any) => JSON.parse(s));
            const online = devices.some(d => d.status === 'online');
            const idle = !online && devices.some(d => d.status === 'idle');
            roster.push({ userId: mid, status: online ? 'online' : (idle ? 'idle' : 'offline'), lastSeen: Math.max(...devices.map(d=>d.lastSeen)) });
          } else roster.push({ userId: mid, status: 'offline', lastSeen: 0 });
        });
      }
      ack({ roster });
    });

    socket.on('hb', async () => {
      await touchPresence(userId, deviceId, 'online');
    });
    socket.on('idle', async () => {
      await setDeviceStatus(userId, deviceId, 'idle');
      await refreshUserStatus(userId);
    });
    socket.on('active', async () => {
      await setDeviceStatus(userId, deviceId, 'online');
      await refreshUserStatus(userId);
    });

    socket.on('disconnect', async () => {
      await redis.hdel(`presence:${userId}`, `device:${deviceId}`);
      const remaining = await redis.hlen(`presence:${userId}`);
      if (remaining === 0) {
        // schedule offline after grace
        const t = setTimeout(async () => {
          pendingOffline.delete(userId);
          const stillEmpty = await redis.hlen(`presence:${userId}`);
          if (stillEmpty === 0) {
            await redis.publish('presence:change', JSON.stringify({ userId, status: 'offline', lastSeen: Date.now() }));
          }
        }, GRACE_MS);
        pendingOffline.set(userId, t);
      }
    });
  });
}

async function touchPresence(userId: string, deviceId: string, status: 'online'|'idle') {
  const val = JSON.stringify({ lastSeen: Date.now(), status, deviceId });
  await redis.hset(`presence:${userId}`, `device:${deviceId}`, val);
  await redis.expire(`presence:${userId}`, DEVICE_TTL_S);
}
async function setDeviceStatus(userId: string, deviceId: string, status: 'online'|'idle') {
  await touchPresence(userId, deviceId, status);
}
async function refreshUserStatus(userId: string) {
  const all = await redis.hgetall(`presence:${userId}`);
  const devices = Object.values(all).map(s => JSON.parse(s));
  const status = devices.some((d:any) => d.status === 'online') ? 'online' : 'idle';
  await redis.publish('presence:change', JSON.stringify({ userId, status, lastSeen: Date.now() }));
}

