// src/hooks/usePresence.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getPresenceSock(token:string, deviceId:string) {
  if (sock) return sock;
  sock = io('/presence', { auth: { token }, extraHeaders: { 'x-device-id': deviceId }, transports:['websocket'], reconnection:true });
  return sock;
}

type Status = 'online'|'idle'|'offline';
export function usePresence(token:string, deviceId:string, workspaceIds:string[]) {
  const [roster, setRoster] = useState<Record<string, { status: Status; lastSeen: number }>>({});
  const idleTimerRef = useRef<number | null>(null);
  const isIdleRef = useRef(false);
  const wsIdsKey = workspaceIds.join(',');

  useEffect(() => {
    const socket = getPresenceSock(token, deviceId);
    const onConnect = () => {
      socket.emit('ws:subscribe', { workspaceIds }, (res: any) => {
        setRoster(Object.fromEntries(res.roster.map((r: any) => [r.userId, { status: r.status, lastSeen: r.lastSeen }])));
      });
    };
    const onChange = (e: { userId: string; status: Status; lastSeen: number }) => {
      setRoster(prev => ({ ...prev, [e.userId]: { status: e.status, lastSeen: e.lastSeen } }));
    };
    socket.on('connect', onConnect);
    socket.on('presence:change', onChange);
    if (socket.connected) onConnect();

    const hb = window.setInterval(() => socket.emit('hb'), 20_000);

    const bumpIdle = () => {
      if (isIdleRef.current) {
        isIdleRef.current = false; socket.emit('active');
      }
      if (idleTimerRef.current) window.clearTimeout(idleTimerRef.current);
      idleTimerRef.current = window.setTimeout(() => {
        isIdleRef.current = true; socket.emit('idle');
      }, 5*60*1000);
    };
    ['mousemove','keydown','touchstart','focus'].forEach(ev => window.addEventListener(ev, bumpIdle, { passive: true }));
    bumpIdle();

    return () => {
      socket.off('connect', onConnect); socket.off('presence:change', onChange);
      window.clearInterval(hb);
      if (idleTimerRef.current) window.clearTimeout(idleTimerRef.current);
      ['mousemove','keydown','touchstart','focus'].forEach(ev => window.removeEventListener(ev, bumpIdle));
    };
  }, [token, deviceId, wsIdsKey]);

  return { roster };
}

