// src/workers/annotationStream.ts
import mongoose from 'mongoose';
import { redis } from '../infra/redis';
import { Annotation } from '../models/Annotation';
import { logger } from '../infra/logger';

export async function runAnnotationStream() {
  let resumeToken = await loadResume();
  while (true) {
    try {
      const stream = Annotation.watch([], { fullDocument: 'updateLookup', resumeAfter: resumeToken });
      for await (const change of stream) {
        resumeToken = change._id as any;
        await redis.set('anno:resume', JSON.stringify(resumeToken));
        const doc = (change as any).fullDocument;
        if (!doc) continue;
        await redis.publish(`anno:doc:${doc.docId}`, JSON.stringify({ type: mapOp(change.operationType), annotation: doc }));
      }
    } catch (e) { logger.error({err:e}, 'anno_stream_err'); await new Promise(r=>setTimeout(r,1000)); }
  }
}
function mapOp(o: string){ return o==='insert'?'created': o==='delete'?'deleted':'updated'; }
async function loadResume() { const v = await redis.get('anno:resume'); return v ? JSON.parse(v) : undefined; }

// src/socket/annotations.namespace.ts
import { Namespace } from 'socket.io';
import { sub } from '../infra/redis';
import { Annotation } from '../models/Annotation';
import { canRead } from '../auth/perms';

export function registerAnnotationsNamespace(nsp: Namespace) {
  nsp.use(authMw); nsp.use(orgMw);
  sub.psubscribe('anno:doc:*');
  sub.on('pmessage', async (_p, ch, payload) => {
    const docId = ch.split(':')[2];
    const evt = JSON.parse(payload);
    const room = `doc:${docId}`;
    const sockets = await nsp.in(room).fetchSockets();
    for (const s of sockets) {
      const viewer = (s.data as any).user;
      if (canSeeAnnotation(evt.annotation, viewer)) {
        s.emit('annotation:change', evt);
      }
    }
  });

  nsp.on('connection', (socket) => {
    socket.on('doc:open', async ({ docId, page=0, pageSize=200 }, ack) => {
      if (!await canRead(socket.data.user, docId)) return ack({ error: 'forbidden' });
      await socket.join(`doc:${docId}`);
      const all = await Annotation.find({ docId, deletedAt: null }).sort({ createdAt: 1 }).skip(page*pageSize).limit(pageSize).lean();
      const visible = all.filter(a => canSeeAnnotation(a, socket.data.user));
      const head = await Annotation.findOne({ docId }).sort({ updatedAt: -1 }).select('updatedAt').lean();
      ack({ annotations: visible, lastUpdatedAt: head?.updatedAt ?? null });
    });

    socket.on('doc:sync', async ({ docId, since }, ack) => {
      const updates = await Annotation.find({ docId, updatedAt: { $gt: new Date(since) } }).sort({ updatedAt: 1 }).limit(500).lean();
      ack({ updates: updates.filter(a => canSeeAnnotation(a, socket.data.user)) });
    });

    socket.on('annotation:create', async (input, ack) => {
      if (!await canRead(socket.data.user, input.docId)) return ack({ error: 'forbidden' });
      const doc = await Annotation.create({ ...input, authorId: socket.data.user.id, orgId: socket.data.user.orgId });
      ack({ annotation: doc.toObject() });
      // broadcast happens via change stream worker — don't double-emit
    });

    socket.on('annotation:update', async ({ id, patch, expectedVersion }, ack) => {
      const updated = await Annotation.findOneAndUpdate(
        { _id: id, version: expectedVersion, authorId: socket.data.user.id },
        { $set: patch, $inc: { version: 1 } }, { new: true },
      );
      if (!updated) return ack({ error: 'conflict_or_forbidden' });
      ack({ annotation: updated.toObject() });
    });

    socket.on('annotation:delete', async ({ id }, ack) => {
      await Annotation.updateOne({ _id: id, authorId: socket.data.user.id }, { $set: { deletedAt: new Date() } });
      ack({ ok: true });
    });
  });
}

function canSeeAnnotation(a: any, viewer: any): boolean {
  if (a.visibility === 'public') return true;
  if (a.orgId !== viewer.orgId) return false;
  if (a.visibility === 'org') return true;
  if (a.visibility === 'team') return a.teamIds.some((t: string) => viewer.teamIds.includes(t));
  if (a.visibility === 'private') return a.authorId === viewer.id;
  return false;
}

