// src/hooks/useAnnotations.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/annotations',{auth:{token},transports:['websocket']}); return sock; }

type Annotation = { _id:string; docId:string; pageIndex:number; kind:string; version:number; quadPoints?:number[][]; deletedAt?:string; [k:string]:any };
export function useAnnotations(docId:string, token:string) {
  const [annotations, setAnnotations] = useState<Map<string, Annotation>>(new Map());
  const lastSyncRef = useRef<string | null>(null);
  const seen = useRef(new Set<string>());

  useEffect(() => {
    const socket = getSock(token);
    const subscribe = () => {
      if (lastSyncRef.current) {
        socket.emit('doc:sync', { docId, since: lastSyncRef.current }, (res:any) => res.updates?.forEach(ingest));
      } else {
        socket.emit('doc:open', { docId }, (res:any) => {
          if (res.error) return;
          const m = new Map<string,Annotation>();
          for (const a of res.annotations) { m.set(a._id, a); seen.current.add(a._id); }
          setAnnotations(m);
          lastSyncRef.current = res.lastUpdatedAt;
        });
      }
    };
    const ingest = (a: Annotation) => {
      lastSyncRef.current = (a as any).updatedAt ?? lastSyncRef.current;
      setAnnotations(prev => {
        const n = new Map(prev);
        if (a.deletedAt) n.delete(a._id); else n.set(a._id, a);
        return n;
      });
    };
    const onChange = (e: { type:string; annotation: Annotation }) => ingest(e.annotation);
    socket.on('connect', subscribe); socket.on('annotation:change', onChange);
    if (socket.connected) subscribe();
    return () => { socket.off('connect', subscribe); socket.off('annotation:change', onChange); };
  }, [docId, token]);

  const create = useCallback((input: Partial<Annotation>) => new Promise<Annotation>((resolve, reject) => {
    getSock(token).emit('annotation:create', { ...input, docId }, (res:any) => res.error ? reject(new Error(res.error)) : resolve(res.annotation));
  }), [docId, token]);

  const update = useCallback((id:string, patch:any, expectedVersion:number) => new Promise<Annotation>((resolve, reject) => {
    setAnnotations(prev => { const cur = prev.get(id); if (!cur) return prev; const n = new Map(prev); n.set(id, { ...cur, ...patch }); return n; });
    getSock(token).emit('annotation:update', { id, patch, expectedVersion }, (res:any) => { if (res.error) { reject(new Error(res.error)); /* server change stream will restore canonical */ } else resolve(res.annotation); });
  }), [token]);

  const remove = useCallback((id:string) => {
    setAnnotations(prev => { const n = new Map(prev); n.delete(id); return n; });
    getSock(token).emit('annotation:delete', { id }, () => {});
  }, [token]);

  return { annotations: [...annotations.values()], create, update, remove };
}

