// src/services/notificationService.ts
import { pool } from '../infra/pg';
import { Draft } from '../models/Draft';
import { Queue } from 'bullmq';
import { redis } from '../infra/redis';
import { io } from '../server';

const deliverQ = new Queue('deliver', { connection: redis });
const emailQ = new Queue('email', { connection: redis });

export async function enqueueNotification(userId: string, payload: { type:string; targetType:string; targetId:string; actorId:string; body:string }) {
  const draft = await Draft.findOneAndUpdate(
    { userId, targetType: payload.targetType, targetId: payload.targetId, flushedAt: { $exists: false } },
    { $setOnInsert: { firstAt: new Date(), type: payload.type, body: payload.body }, $addToSet: { actorIds: payload.actorId }, $set: { lastAt: new Date() } },
    { upsert: true, new: true },
  );
  // schedule flush at firstAt + 5min, unless 10 actors reached
  if (draft.actorIds.length >= 10) await flushDraft(String(draft._id));
  else await deliverQ.add('flush', { draftId: String(draft._id) }, { delay: Math.max(0, draft.firstAt.getTime() + 5*60_000 - Date.now()), jobId: `flush:${draft._id}` });
}

export async function flushDraft(draftId: string) {
  const draft = await Draft.findOneAndUpdate({ _id: draftId, flushedAt: { $exists: false } }, { $set: { flushedAt: new Date() } }, { new: true });
  if (!draft) return; // already flushed
  const { rows } = await pool.query(
    `INSERT INTO notifications(user_id, idempotency_key, type, target_type, target_id, actor_ids, actor_count, body)
     VALUES ($1,$2,$3,$4,$5,$6,$7,$8) ON CONFLICT (user_id, idempotency_key) DO NOTHING RETURNING id`,
    [draft.userId, draftId, draft.type, draft.targetType, draft.targetId, draft.actorIds, draft.actorIds.length, draft.body],
  );
  if (rows.length === 0) return; // dedup
  await deliverQ.add('deliver', { notifId: String(rows[0].id), userId: draft.userId }, { jobId: `deliver:${rows[0].id}` });
}

export function registerDeliverWorker() {
  const { Worker } = require('bullmq');
  new Worker('deliver', async (job: any) => {
    if (job.name === 'flush') return flushDraft(job.data.draftId);
    const { notifId, userId } = job.data;
    const { rows } = await pool.query('SELECT id, type, body, created_at, actor_ids FROM notifications WHERE id=$1', [notifId]);
    if (!rows[0]) return;
    const notif = { id: String(rows[0].id), type: rows[0].type, body: rows[0].body, createdAt: rows[0].created_at, actors: rows[0].actor_ids.map(String) };
    const room = `user:${userId}`;
    const sockets = await io.of('/notifications').in(room).fetchSockets();
    if (sockets.length > 0) {
      io.of('/notifications').to(room).emit('notif:new', notif);
      await pool.query('UPDATE notifications SET in_app_delivered_at=now() WHERE id=$1', [notifId]);
    } else {
      // no sessions: schedule email after 5min, cancel if delivered in-app meanwhile
      await emailQ.add('send', { notifId, userId }, { delay: 5*60_000, jobId: `email:${notifId}` });
    }
  }, { connection: redis });

  new Worker('email', async (job: any) => {
    const { rows } = await pool.query('SELECT id, type, body, in_app_delivered_at, email_dispatched_at FROM notifications WHERE id=$1 FOR UPDATE', [job.data.notifId]);
    if (!rows[0] || rows[0].in_app_delivered_at || rows[0].email_dispatched_at) return; // already delivered
    await pool.query('UPDATE notifications SET email_dispatched_at=now() WHERE id=$1', [job.data.notifId]);
    await sendEmail(job.data.userId, rows[0]);
  }, { connection: redis });
}

// src/socket/notifications.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { Queue } from 'bullmq';
import { redis } from '../infra/redis';
const deliverQ = new Queue('deliver', { connection: redis });
const emailQ = new Queue('email', { connection: redis });

export function registerNotifNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', async (socket) => {
    const userId = socket.data.user.id;
    await socket.join(`user:${userId}`);
    socket.on('subscribe', async ({ sinceId }, ack) => {
      const { rows } = await pool.query('SELECT id,type,body,created_at,actor_ids,read_at FROM notifications WHERE user_id=$1 AND id > $2 ORDER BY id DESC LIMIT 100', [userId, sinceId ?? 0]);
      ack({ notifications: rows.reverse(), unreadCount: rows.filter(r=>!r.read_at).length });
    });
    socket.on('notif:read', async ({ id }, ack) => {
      await pool.query('UPDATE notifications SET read_at = COALESCE(read_at, now()) WHERE id=$1 AND user_id=$2', [id, userId]);
      // cancel any pending email since user is clearly online
      try { await emailQ.remove(`email:${id}`); } catch {}
      nsp.to(`user:${userId}`).emit('notif:read', { id });
      ack?.({ ok: true });
    });
    socket.on('notif:read-all', async () => {
      await pool.query('UPDATE notifications SET read_at = now() WHERE user_id=$1 AND read_at IS NULL', [userId]);
      nsp.to(`user:${userId}`).emit('notif:read-all');
    });
  });
}

