let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/notifications',{auth:{token},transports:['websocket']}); return sock; }

type Notif = { id:string; type:string; body:string; createdAt:string; actors:string[]; read_at?:string };
export function useNotifications(token:string) {
  const [items, setItems] = useState<Notif[]>([]);
  const [unread, setUnread] = useState(0);
  const lastIdRef = useRef<string>('0');

  useEffect(() => {
    const socket = getSock(token);
    const subscribe = () => socket.emit('subscribe', { sinceId: lastIdRef.current }, (res:any) => {
      setItems(prev => [...res.notifications, ...prev.filter(p => !res.notifications.find((n:Notif)=>n.id===p.id))]);
      setUnread(prev => prev + res.unreadCount);
      if (res.notifications.length) lastIdRef.current = res.notifications[res.notifications.length-1].id;
    });
    const onNew = (n: Notif) => {
      lastIdRef.current = n.id > lastIdRef.current ? n.id : lastIdRef.current;
      setItems(prev => [n, ...prev]);
      setUnread(u => u + 1);
    };
    const onRead = ({ id }: { id: string }) => {
      setItems(prev => prev.map(n => n.id === id ? { ...n, read_at: new Date().toISOString() } : n));
      setUnread(u => Math.max(0, u - 1));
    };
    const onReadAll = () => { setItems(prev => prev.map(n => ({ ...n, read_at: new Date().toISOString() }))); setUnread(0); };
    socket.on('connect', subscribe);
    socket.on('notif:new', onNew); socket.on('notif:read', onRead); socket.on('notif:read-all', onReadAll);
    if (socket.connected) subscribe();
    return () => { socket.off('connect', subscribe); socket.off('notif:new', onNew); socket.off('notif:read', onRead); socket.off('notif:read-all', onReadAll); };
  }, [token]);

  const markRead = useCallback((id:string) => getSock(token).emit('notif:read', { id }), [token]);
  const markAllRead = useCallback(() => getSock(token).emit('notif:read-all'), [token]);
  return { items, unread, markRead, markAllRead };
}

