// src/ingester/sensor.ts
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { logger } from '../infra/logger';
const BATCH = 500; const FLUSH_MS = 100;
const thresholds = new Map<string, { min:number; max:number }>(); // metric → bounds, loaded on boot
let buffer: any[] = [];
let timer: NodeJS.Timeout | null = null;

export function ingest(event: { deviceId:string; plantId:number; ts:number; metric:string; value:number }) {
  buffer.push(event);
  // anomaly inline
  const th = thresholds.get(event.metric);
  if (th && (event.value < th.min || event.value > th.max)) {
    pool.query('INSERT INTO alerts(plant_id, device_id, metric, threshold, value, ts) VALUES ($1,$2,$3,$4,$5,to_timestamp($6/1000.0))',
      [event.plantId, event.deviceId, event.metric, event.value < th.min ? th.min : th.max, event.value, event.ts]).then(() => {
        redis.publish(`alerts:plant:${event.plantId}`, JSON.stringify(event));
      }).catch(e => logger.error({err:e},'alert_insert'));
  }
  if (buffer.length >= BATCH) flush();
  else if (!timer) timer = setTimeout(flush, FLUSH_MS);
}
async function flush() {
  if (timer) { clearTimeout(timer); timer = null; }
  if (!buffer.length) return;
  const events = buffer; buffer = [];
  const values = events.map((e, i) => `($${i*5+1},$${i*5+2},to_timestamp($${i*5+3}/1000.0),$${i*5+4},$${i*5+5})`).join(',');
  const params = events.flatMap(e => [e.deviceId, e.plantId, e.ts, e.metric, e.value]);
  try {
    await pool.query(`INSERT INTO sensor_events(device_id,plant_id,ts,metric,value) VALUES ${values} ON CONFLICT DO NOTHING`, params);
    // group by plant for fan-out
    const byPlant = new Map<number, any[]>();
    for (const e of events) { (byPlant.get(e.plantId) ?? byPlant.set(e.plantId, []).get(e.plantId))!.push(e); }
    for (const [pid, batch] of byPlant) await redis.publish(`tel:plant:${pid}`, JSON.stringify(batch));
  } catch (e) { logger.error({err:e, count: events.length}, 'ingest_flush_fail'); /* could re-enqueue */ }
}

// src/socket/telemetry.namespace.ts
import { Namespace } from 'socket.io';
import { sub } from '../infra/redis';
import { pool } from '../infra/pg';

type Sub = { plantId:number; hz:number; lastSentAtPerKey: Map<string, number> };
const subs = new Map<string, Sub>();

export function registerTelemetryNamespace(nsp: Namespace) {
  nsp.use(authMw);
  sub.psubscribe('tel:plant:*');
  sub.on('pmessage', async (_p, ch, payload) => {
    const plantId = Number(ch.split(':')[2]);
    const batch = JSON.parse(payload);
    const room = `plant:${plantId}`;
    const sockets = await nsp.in(room).fetchSockets();
    for (const s of sockets) {
      const cfg = subs.get(s.id); if (!cfg || cfg.plantId !== plantId) continue;
      const minInterval = 1000 / cfg.hz;
      const send: any[] = [];
      for (const e of batch) {
        const key = `${e.deviceId}:${e.metric}`;
        const last = cfg.lastSentAtPerKey.get(key) ?? 0;
        if (e.ts - last >= minInterval) { send.push(e); cfg.lastSentAtPerKey.set(key, e.ts); }
      }
      if (send.length) s.volatile.emit('tick', send);
    }
  });
  nsp.on('connection', (socket) => {
    socket.on('subscribe', async ({ plantId, hz=10 }, ack) => {
      if (!await canViewPlant(socket.data.user.id, plantId)) return ack({ error: 'forbidden' });
      await socket.join(`plant:${plantId}`);
      subs.set(socket.id, { plantId, hz: Math.min(10, Math.max(1, hz)), lastSentAtPerKey: new Map() });
      ack({ ok: true });
    });
    socket.on('replay', async ({ plantId, t0, t1, hz }, ack) => {
      const view = hz <= 1 ? 'sensor_1m' : hz <= 5 ? 'sensor_1s' : 'sensor_events';
      const { rows } = await pool.query(`SELECT * FROM ${view} WHERE plant_id=$1 AND ${view==='sensor_events'?'ts':'bucket'} BETWEEN $2 AND $3 ORDER BY 1 LIMIT 50000`, [plantId, new Date(t0), new Date(t1)]);
      ack({ rows });
    });
    socket.on('disconnect', () => subs.delete(socket.id));
  });
}

