// src/hooks/useTelemetry.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/telemetry',{auth:{token},transports:['websocket']}); return sock; }

type Tick = { deviceId:string; metric:string; ts:number; value:number };
export function useTelemetry(plantId:number, hz:number, token:string) {
  const [series, setSeries] = useState<Map<string, Tick[]>>(new Map());
  const bufRef = useRef<Tick[]>([]);
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    const socket = getSock(token);
    const subscribe = () => socket.emit('subscribe', { plantId, hz }, () => {});
    const onTick = (batch: Tick[]) => {
      bufRef.current.push(...batch);
      if (rafRef.current == null) rafRef.current = requestAnimationFrame(() => {
        rafRef.current = null;
        const drained = bufRef.current; bufRef.current = [];
        setSeries(prev => {
          const n = new Map(prev);
          for (const t of drained) {
            const key = `${t.deviceId}:${t.metric}`;
            const arr = n.get(key) ?? [];
            arr.push(t);
            if (arr.length > 600) arr.splice(0, arr.length - 600); // cap 1min at 10Hz
            n.set(key, arr);
          }
          return n;
        });
      });
    };
    socket.on('connect', subscribe); socket.on('tick', onTick);
    if (socket.connected) subscribe();
    return () => { socket.off('connect', subscribe); socket.off('tick', onTick); if (rafRef.current) cancelAnimationFrame(rafRef.current); };
  }, [plantId, hz, token]);

  return { series };
}

