// src/socket/rtc.namespace.ts
import { Namespace } from 'socket.io';
import { Room } from '../models/Room';
import { Participant } from '../models/Participant';
import { sfuClient } from '../infra/sfu';
import { v4 as uuid } from 'uuid';

export function registerRtcNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    let participantId: string | null = null;
    let roomId: string | null = null;

    socket.on('room:join', async ({ roomId: rid, reconnectToken, displayName }, ack) => {
      try {
        let p;
        if (reconnectToken) {
          p = await Participant.findOneAndUpdate({ reconnectToken, leftAt: null }, { $set: { lastSeenAt: new Date() } }, { new: true });
          if (!p) return ack({ error: 'reconnect_failed' });
          rid = p.roomId;
        } else {
          if (!await canJoinRoom(socket.data.user.id, rid)) return ack({ error: 'forbidden' });
          const room = await Room.findOneAndUpdate({ _id: rid, endedAt: null }, { $setOnInsert: { sfuNodeId: await sfuClient.pickNode() } }, { upsert: true, new: true });
          p = await Participant.create({ _id: uuid(), roomId: rid, userId: socket.data.user.id, displayName, reconnectToken: uuid() });
        }
        participantId = String(p._id); roomId = rid;
        (socket.data as any).participantId = participantId;
        await socket.join(`room:${rid}`);
        const others = await Participant.find({ roomId: rid, leftAt: null, _id: { $ne: participantId } }).lean();
        socket.to(`room:${rid}`).emit('participant:joined', { participant: p.toObject() });
        const room = await Room.findById(rid).lean();
        ack({ self: p.toObject(), others, room });
      } catch (e) { ack({ error: 'join_failed' }); }
    });

    socket.on('transport:create', async ({ direction }, ack) => {
      if (!participantId || !roomId) return ack({ error: 'not_joined' });
      const room = await Room.findById(roomId).lean();
      const transport = await sfuClient.createTransport(room!.sfuNodeId, roomId, participantId);
      const setField = direction === 'send' ? 'sendTransportId' : 'recvTransportId';
      await Participant.updateOne({ _id: participantId }, { $set: { [setField]: transport.id } });
      ack({ transport });
    });

    socket.on('sdp', async ({ to, sdp }) => {
      if (!roomId) return;
      const target = await Participant.findOne({ _id: to, roomId, leftAt: null }).lean();
      if (!target) return;
      // emit to target socket(s): find socket(s) by participant id
      const sockets = await nsp.in(`room:${roomId}`).fetchSockets();
      for (const s of sockets) if ((s.data as any).participantId === to) s.emit('sdp', { from: participantId, sdp });
    });
    socket.on('ice', async ({ to, candidate }) => {
      if (!roomId) return;
      const sockets = await nsp.in(`room:${roomId}`).fetchSockets();
      for (const s of sockets) if ((s.data as any).participantId === to) s.emit('ice', { from: participantId, candidate });
    });

    socket.on('state:update', async (patch, ack) => {
      if (!participantId || !roomId) return ack?.({ error: 'not_joined' });
      const allow = ['mic','cam','screenSharing'].filter(k => k in patch);
      const $set: any = {}; for (const k of allow) $set[k] = !!patch[k];
      await Participant.updateOne({ _id: participantId }, { $set });
      nsp.to(`room:${roomId}`).emit('participant:state', { participantId, patch: $set });
      ack?.({ ok: true });
    });

    socket.on('recording:start', async (_, ack) => {
      if (!roomId) return ack({ error: 'not_joined' });
      const room = await Room.findOneAndUpdate({ _id: roomId, recordingState: 'off' }, { $set: { recordingState: 'requested', recordingStartedBy: socket.data.user.id } }, { new: true });
      if (!room) return ack({ error: 'already_recording' });
      sfuClient.startRecording(room.sfuNodeId, roomId).then(() => Room.updateOne({_id:roomId},{$set:{recordingState:'active'}}));
      nsp.to(`room:${roomId}`).emit('recording:state', { state: 'requested', by: socket.data.user.id });
      ack({ ok: true });
    });

    socket.on('disconnect', async () => {
      if (!participantId) return;
      // grace period: don't mark left immediately
      setTimeout(async () => {
        const p = await Participant.findOne({ _id: participantId }).lean();
        if (p && (Date.now() - new Date(p.lastSeenAt).getTime()) > 25_000) {
          await Participant.updateOne({ _id: participantId, leftAt: null }, { $set: { leftAt: new Date() } });
          if (roomId) nsp.to(`room:${roomId}`).emit('participant:left', { participantId });
          await sfuClient.releaseTransports(participantId);
        }
      }, 30_000);
    });
  });
}

