// src/hooks/useCallRoom.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
import { Device } from 'mediasoup-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/rtc',{auth:{token},transports:['websocket'],reconnection:true}); return sock; }

type Participant = { _id:string; userId:string; displayName:string; mic:boolean; cam:boolean; screenSharing:boolean };
export function useCallRoom(roomId:string, token:string, displayName:string) {
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [me, setMe] = useState<Participant | null>(null);
  const reconnectTokenRef = useRef<string | null>(null);
  const deviceRef = useRef<Device | null>(null);
  const sendTransportRef = useRef<any>(null);
  const producersRef = useRef<any[]>([]);

  useEffect(() => {
    const socket = getSock(token);
    const join = () => socket.emit('room:join', { roomId, reconnectToken: reconnectTokenRef.current, displayName }, async (res:any) => {
      if (res.error) return;
      reconnectTokenRef.current = res.self.reconnectToken;
      setMe(res.self); setParticipants(res.others);
      if (!deviceRef.current) {
        deviceRef.current = new Device();
        // (router rtpCapabilities fetched out-of-band in real impl)
        socket.emit('transport:create', { direction: 'send' }, async (r:any) => {
          const t = deviceRef.current!.createSendTransport(r.transport);
          sendTransportRef.current = t;
          // produce mic + cam tracks; omitted for brevity
        });
      }
    });
    const onJoined = ({ participant }: any) => setParticipants(p => [...p, participant]);
    const onLeft = ({ participantId }: any) => setParticipants(p => p.filter(x => x._id !== participantId));
    const onState = ({ participantId, patch }: any) => setParticipants(p => p.map(x => x._id === participantId ? { ...x, ...patch } : x));
    const onSdp = async ({ from, sdp }: any) => { /* apply remote SDP via mediasoup-client consumer */ };
    const onIce = async ({ from, candidate }: any) => { /* add ICE */ };
    socket.on('connect', join);
    socket.on('participant:joined', onJoined);
    socket.on('participant:left', onLeft);
    socket.on('participant:state', onState);
    socket.on('sdp', onSdp); socket.on('ice', onIce);
    if (socket.connected) join();
    return () => {
      socket.off('connect', join);
      socket.off('participant:joined', onJoined); socket.off('participant:left', onLeft); socket.off('participant:state', onState);
      socket.off('sdp', onSdp); socket.off('ice', onIce);
      // do NOT close media transports — reconnect should reuse
    };
  }, [roomId, token, displayName]);

  const toggleMic = useCallback(() => {
    if (!me) return; const next = !me.mic;
    setMe({ ...me, mic: next });
    getSock(token).emit('state:update', { mic: next }, () => {});
    producersRef.current.forEach((p:any) => p.kind === 'audio' && (next ? p.resume() : p.pause()));
  }, [me, token]);

  return { me, participants, toggleMic };
}

