// src/socket/forms.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import type { PoolClient } from 'pg';

type Held = { fieldId: string; client: PoolClient };
const heldBySocket = new Map<string, Map<string, Held>>(); // socketId → fieldId → {client}

export function registerFormsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('form:open', async ({ formId }, ack) => {
      if (!await canEditForm(userId, formId)) return ack({ error: 'forbidden' });
      await socket.join(`form:${formId}`);
      const { rows: fr } = await pool.query('SELECT id, version, fields FROM forms WHERE id=$1', [formId]);
      if (!fr[0]) return ack({ error: 'no_form' });
      const locksKey = `form:locks:${formId}`;
      const locks = await redis.hgetall(locksKey); // fieldId → userId
      ack({ form: fr[0], locks });
    });

    socket.on('field:focus', async ({ formId, fieldId }, ack) => {
      const existing = await redis.hget(`form:locks:${formId}`, fieldId);
      if (existing && existing !== userId) return ack({ ok: false, lockedBy: existing });
      // attempt pg session lock — we hold the client for the duration
      const client = await pool.connect();
      try {
        const r = await client.query('SELECT pg_try_advisory_lock(hashtext($1), hashtext($2)) AS got', [`form:${formId}`, fieldId]);
        if (!r.rows[0].got) { client.release(); return ack({ ok: false, lockedBy: existing }); }
        // race: set Redis only after pg lock acquired
        const setOk = await redis.hsetnx(`form:locks:${formId}`, fieldId, userId);
        if (!setOk) {
          await client.query('SELECT pg_advisory_unlock(hashtext($1), hashtext($2))', [`form:${formId}`, fieldId]);
          client.release();
          const owner = await redis.hget(`form:locks:${formId}`, fieldId);
          return ack({ ok: false, lockedBy: owner });
        }
        await redis.expire(`form:locks:${formId}`, 3600);
        if (!heldBySocket.has(socket.id)) heldBySocket.set(socket.id, new Map());
        heldBySocket.get(socket.id)!.set(fieldId, { fieldId, client });
        socket.to(`form:${formId}`).emit('field:locked', { formId, fieldId, userId });
        ack({ ok: true });
      } catch (e) { client.release(); ack({ ok: false, error: 'server' }); }
    });

    socket.on('field:blur', async ({ formId, fieldId }, ack) => {
      await releaseLock(socket.id, formId, fieldId, nsp, userId);
      ack?.({ ok: true });
    });

    socket.on('field:save', async ({ formId, fieldId, value, expectedVersion }, ack) => {
      const held = heldBySocket.get(socket.id)?.get(fieldId);
      if (!held) return ack({ error: 'not_locked' });
      try {
        await held.client.query('BEGIN');
        await held.client.query('SELECT pg_advisory_xact_lock(hashtext($1))', [`form:${formId}`]); // serialize per-form saves
        const { rows } = await held.client.query('SELECT version, fields FROM forms WHERE id=$1 FOR UPDATE', [formId]);
        if (!rows[0]) { await held.client.query('ROLLBACK'); return ack({ error: 'no_form' }); }
        if (rows[0].version !== expectedVersion) {
          await held.client.query('ROLLBACK');
          return ack({ error: 'version_mismatch', currentVersion: rows[0].version, currentFields: rows[0].fields });
        }
        const prevValue = rows[0].fields?.[fieldId] ?? null;
        const newVersion = rows[0].version + 1;
        await held.client.query('UPDATE forms SET fields = jsonb_set(fields, $1, $2), version = $3, updated_at = now() WHERE id = $4', [`{${fieldId}}`, JSON.stringify(value), newVersion, formId]);
        await held.client.query('INSERT INTO form_history(form_id,version,field_path,prev_value,new_value,changed_by) VALUES ($1,$2,$3,$4,$5,$6)', [formId, newVersion, fieldId, prevValue, value, userId]);
        await held.client.query('COMMIT');
        nsp.to(`form:${formId}`).emit('field:updated', { formId, fieldId, value, version: newVersion, userId });
        ack({ version: newVersion });
      } catch (e) { await held.client.query('ROLLBACK'); ack({ error: 'server' }); }
    });

    socket.on('disconnect', async () => {
      const held = heldBySocket.get(socket.id);
      if (!held) return;
      for (const [fieldId, h] of held) {
        try { await h.client.query('SELECT pg_advisory_unlock_all()'); } catch {}
        try { h.client.release(); } catch {}
        const formIdMatch = await redis.hget(`form:locks:scan`, ''); // simplification: in real impl we'd track formId per held
        // Better: store formId alongside Held
      }
      heldBySocket.delete(socket.id);
      // Improved: iterate held with stored formId and emit field:released + redis.hdel
    });
  });
}

async function releaseLock(socketId: string, formId: string, fieldId: string, nsp: Namespace, userId: string) {
  const held = heldBySocket.get(socketId)?.get(fieldId);
  if (!held) return;
  try { await held.client.query('SELECT pg_advisory_unlock(hashtext($1), hashtext($2))', [`form:${formId}`, fieldId]); } catch {}
  held.client.release();
  heldBySocket.get(socketId)!.delete(fieldId);
  await redis.hdel(`form:locks:${formId}`, fieldId);
  nsp.to(`form:${formId}`).emit('field:released', { formId, fieldId, userId });
}

