import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/forms',{auth:{token},transports:['websocket'],reconnection:true}); return sock; }

type FormState = { fields: Record<string, any>; version: number; locks: Record<string, string> };
export function useFormCollab(formId:string, token:string, myUserId:string) {
  const [state, setState] = useState<FormState>({ fields: {}, version: 0, locks: {} });
  const localValuesRef = useRef<Record<string, any>>({});
  const saveTimersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  useEffect(() => {
    const socket = getSock(token);
    const open = () => socket.emit('form:open', { formId }, (res:any) => {
      if (res.error) return;
      setState({ fields: res.form.fields ?? {}, version: res.form.version, locks: res.locks ?? {} });
    });
    const onLocked = ({ fieldId, userId }:any) => setState(s => ({ ...s, locks: { ...s.locks, [fieldId]: userId } }));
    const onReleased = ({ fieldId }:any) => setState(s => { const l = { ...s.locks }; delete l[fieldId]; return { ...s, locks: l }; });
    const onUpdated = ({ fieldId, value, version }:any) => setState(s => ({ ...s, fields: { ...s.fields, [fieldId]: value }, version }));
    socket.on('connect', open);
    socket.on('field:locked', onLocked); socket.on('field:released', onReleased); socket.on('field:updated', onUpdated);
    if (socket.connected) open();
    return () => {
      // release all my held locks on unmount
      Object.entries(state.locks).filter(([,u]) => u === myUserId).forEach(([fid]) => socket.emit('field:blur', { formId, fieldId: fid }));
      socket.off('connect', open); socket.off('field:locked', onLocked); socket.off('field:released', onReleased); socket.off('field:updated', onUpdated);
      saveTimersRef.current.forEach(t => clearTimeout(t)); saveTimersRef.current.clear();
    };
  }, [formId, token, myUserId, state.locks]);

  const focusField = useCallback((fieldId:string) => new Promise<boolean>((resolve) => {
    getSock(token).emit('field:focus', { formId, fieldId }, (res:any) => resolve(!!res.ok));
  }), [formId, token]);

  const blurField = useCallback((fieldId:string) => {
    const t = saveTimersRef.current.get(fieldId); if (t) { clearTimeout(t); saveTimersRef.current.delete(fieldId); flushField(fieldId); }
    getSock(token).emit('field:blur', { formId, fieldId }, () => {});
  }, [formId, token]);

  const changeField = useCallback((fieldId:string, value:any) => {
    localValuesRef.current[fieldId] = value;
    const existing = saveTimersRef.current.get(fieldId);
    if (existing) clearTimeout(existing);
    saveTimersRef.current.set(fieldId, setTimeout(() => flushField(fieldId), 2000));
  }, []);

  const flushField = useCallback((fieldId:string) => {
    saveTimersRef.current.delete(fieldId);
    const value = localValuesRef.current[fieldId];
    getSock(token).emit('field:save', { formId, fieldId, value, expectedVersion: state.version }, (res:any) => {
      if (res.error === 'version_mismatch') {
        // refresh and re-attempt — keep local value but warn user
        setState(s => ({ ...s, version: res.currentVersion, fields: res.currentFields }));
      }
    });
  }, [formId, token, state.version]);

  return { state, focusField, blurField, changeField };
}

