// src/workers/transcode.ts
import { Worker, Queue } from 'bullmq';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
import { exec } from 'child_process';
import { promisify } from 'util';

export const transcodeQ = new Queue('transcode', { connection: redis });
const CHECK_CANCEL_EVERY_MS = 1000;

export function startTranscodeWorker() {
  new Worker('transcode', async (job: any) => {
    const { jobId } = job.data;
    await pool.query("UPDATE jobs SET status='running', started_at=COALESCE(started_at, now()) WHERE id=$1", [jobId]);
    let cancelled = false;
    const cancelInterval = setInterval(async () => {
      const flag = await redis.get(`job:cancel:${jobId}`);
      if (flag) cancelled = true;
    }, CHECK_CANCEL_EVERY_MS);
    try {
      for (const stage of ['probe','transcode','thumbnail','publish']) {
        if (cancelled) throw new Error('cancelled');
        await pool.query(
          "UPDATE jobs SET stages = stages || jsonb_build_array(jsonb_build_object('name',$1::text,'status','running','startedAt',to_jsonb(now()))) WHERE id=$2",
          [stage, jobId],
        );
        await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'stage', stage, status: 'running' }));
        await runStage(jobId, stage, async (pct) => {
          await redis.set(`job:${jobId}:progress`, JSON.stringify({ stage, progress: pct }), 'EX', 3600);
          // throttle publish to 1Hz
          const last = await redis.get(`job:${jobId}:lastpub`);
          if (!last || Date.now() - Number(last) > 1000) {
            await redis.set(`job:${jobId}:lastpub`, String(Date.now()), 'EX', 60);
            await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'progress', stage, progress: pct }));
          }
        }, () => cancelled);
        await pool.query(
          `UPDATE jobs SET stages = (SELECT jsonb_agg(CASE WHEN x->>'name'=$1 THEN x||jsonb_build_object('status','done','progress',100,'endedAt',to_jsonb(now())) ELSE x END) FROM jsonb_array_elements(stages) x) WHERE id=$2`,
          [stage, jobId],
        );
        await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'stage', stage, status: 'done' }));
      }
      await pool.query("UPDATE jobs SET status='succeeded', ended_at=now() WHERE id=$1", [jobId]);
      await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'done', status: 'succeeded' }));
    } catch (e: any) {
      const isCancel = e.message === 'cancelled';
      if (isCancel) {
        await pool.query("UPDATE jobs SET status='cancelled', ended_at=now() WHERE id=$1", [jobId]);
        await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'done', status: 'cancelled' }));
      } else {
        const r = await pool.query('UPDATE jobs SET attempt=attempt+1 WHERE id=$1 RETURNING attempt', [jobId]);
        const attempt = r.rows[0].attempt;
        if (attempt >= 3) {
          await pool.query('BEGIN');
          await pool.query("UPDATE jobs SET status='failed', ended_at=now() WHERE id=$1", [jobId]);
          await pool.query('INSERT INTO dead_letters(job_id, attempt, error, payload) SELECT id, $1, $2, payload FROM jobs WHERE id=$3', [attempt, String(e), jobId]);
          await pool.query('COMMIT');
          await redis.publish(`jobs:job:${jobId}`, JSON.stringify({ type: 'done', status: 'failed', error: String(e) }));
        } else {
          // BullMQ will retry with backoff
          throw e;
        }
      }
    } finally {
      clearInterval(cancelInterval);
      await redis.del(`job:cancel:${jobId}`);
    }
  }, { connection: redis, concurrency: 4 });
}

async function runStage(jobId:number, stage:string, onProg:(p:number)=>Promise<void>, isCancelled:()=>boolean) {
  // example for transcode using ffmpeg duration probing
  if (stage === 'probe') { for (let i = 10; i <= 100; i += 30) { if (isCancelled()) throw new Error('cancelled'); await onProg(i); await new Promise(r=>setTimeout(r,200)); } return; }
  // real ffmpeg invocation with -progress pipe parsed here
  for (let i = 0; i <= 100; i += 5) { if (isCancelled()) throw new Error('cancelled'); await onProg(i); await new Promise(r=>setTimeout(r,300)); }
}

// src/socket/jobs.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';
import { redis, sub } from '../infra/redis';

export function registerJobsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  sub.psubscribe('jobs:job:*');
  sub.on('pmessage', (_p, ch, payload) => {
    const jobId = ch.split(':')[2];
    const data = JSON.parse(payload);
    nsp.to(`job:${jobId}`).emit(`job:${data.type}`, { jobId, ...data });
  });

  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('jobs:subscribe', async (_,ack) => {
      await socket.join(`user:${userId}:jobs`);
      const { rows } = await pool.query("SELECT id,type,status,stages,enqueued_at FROM jobs WHERE user_id=$1 AND status IN ('queued','running','cancel_requested') ORDER BY enqueued_at DESC LIMIT 50", [userId]);
      ack({ jobs: rows });
    });
    socket.on('job:subscribe', async ({ jobId }, ack) => {
      const { rows } = await pool.query('SELECT id,user_id,type,status,stages FROM jobs WHERE id=$1', [jobId]);
      if (!rows[0] || Number(rows[0].user_id) !== userId) return ack({ error: 'forbidden' });
      await socket.join(`job:${jobId}`);
      const progress = await redis.get(`job:${jobId}:progress`);
      ack({ job: rows[0], currentProgress: progress ? JSON.parse(progress) : null });
    });
    socket.on('job:cancel', async ({ jobId }, ack) => {
      const r = await pool.query("UPDATE jobs SET status='cancel_requested' WHERE id=$1 AND user_id=$2 AND status IN ('queued','running') RETURNING id", [jobId, userId]);
      if (r.rowCount === 0) return ack({ error: 'not_cancellable' });
      await redis.set(`job:cancel:${jobId}`, '1', 'EX', 600);
      ack({ ok: true });
    });
  });
}

