// src/hooks/useJob.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/jobs',{auth:{token},transports:['websocket']}); return sock; }

type Stage = { name:string; status:string; progress?:number };
type Job = { id:string; type:string; status:string; stages:Stage[]; currentProgress?:{stage:string;progress:number} };

export function useJob(jobId:string, token:string) {
  const [job, setJob] = useState<Job | null>(null);
  useEffect(() => {
    const socket = getSock(token);
    const subscribe = () => socket.emit('job:subscribe', { jobId }, (res:any) => { if (!res.error) setJob({ ...res.job, currentProgress: res.currentProgress }); });
    const onProgress = ({ jobId: jid, stage, progress }:any) => { if (jid !== jobId) return; setJob(j => j ? { ...j, currentProgress: { stage, progress } } : j); };
    const onStage = ({ jobId: jid, stage, status }:any) => { if (jid !== jobId) return; setJob(j => j ? { ...j, stages: j.stages.map(s => s.name === stage ? { ...s, status } : s) } : j); };
    const onDone = ({ jobId: jid, status }:any) => { if (jid !== jobId) return; setJob(j => j ? { ...j, status } : j); };
    socket.on('connect', subscribe);
    socket.on('job:progress', onProgress);
    socket.on('job:stage', onStage);
    socket.on('job:done', onDone);
    if (socket.connected) subscribe();
    return () => { socket.off('connect', subscribe); socket.off('job:progress', onProgress); socket.off('job:stage', onStage); socket.off('job:done', onDone); };
  }, [jobId, token]);
  const cancel = useCallback(() => new Promise<void>((resolve, reject) => {
    getSock(token).emit('job:cancel', { jobId }, (res:any) => res.error ? reject(new Error(res.error)) : resolve());
  }), [jobId, token]);
  return { job, cancel };
}

