// src/socket/cursors.namespace.ts
import { Namespace } from 'socket.io';
import { redis } from '../infra/redis';
import { Collaborator } from '../models/Collaborator';

export function registerCursorsNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    const displayName = socket.data.user.displayName;
    let fileId: string | null = null;
    let lastEmitTs = 0;
    let floodCount = 0;

    socket.on('file:join', async ({ fileId: fid }, ack) => {
      if (!await canReadFile(userId, fid)) return ack({ error: 'forbidden' });
      fileId = fid;
      await socket.join(`file:${fid}`);
      const color = pickColor(userId);
      await Collaborator.findOneAndUpdate({ _id: `${socket.id}:${userId}` }, { fileId: fid, userId, displayName, color, lastSeenAt: new Date(), joinedAt: new Date() }, { upsert: true });
      const cursors = await redis.hgetall(`cursors:${fid}`);
      const roster = await Collaborator.find({ fileId: fid, lastSeenAt: { $gte: new Date(Date.now() - 60_000) } }).lean();
      socket.to(`file:${fid}`).emit('collab:joined', { userId, displayName, color });
      ack({ roster, cursors: Object.fromEntries(Object.entries(cursors).map(([u,v]) => [u, JSON.parse(v)])) });
    });

    socket.on('cursor:move', async (c: any) => {
      if (!fileId) return;
      const now = Date.now();
      if (now - lastEmitTs < 30) { // 33ms = 30Hz cap
        floodCount++;
        if (floodCount > 50) { socket.disconnect(); return; }
        return;
      }
      lastEmitTs = now; floodCount = 0;
      const data = { userId, line: c.line, col: c.col, selStart: c.selStart, selEnd: c.selEnd, viewportTop: c.viewportTop, viewportBottom: c.viewportBottom, ts: now };
      await redis.hset(`cursors:${fileId}`, userId, JSON.stringify(data));
      await redis.expire(`cursors:${fileId}`, 120);
      socket.to(`file:${fileId}`).emit('cursor:change', data);
      // amplify viewport to followers
      const followers = await Collaborator.find({ fileId, followingUserId: userId }, { _id: 1 }).lean();
      if (followers.length) {
        // we have socketId in _id prefix; fetch sockets in room and filter
        const sockets = await nsp.in(`file:${fileId}`).fetchSockets();
        const followerIds = new Set(followers.map(f => String(f._id).split(':')[0]));
        for (const s of sockets) if (followerIds.has(s.id)) s.emit('follow:viewport', { leaderId: userId, viewportTop: c.viewportTop, viewportBottom: c.viewportBottom });
      }
    });

    socket.on('follow:start', async ({ leaderId }, ack) => {
      if (!fileId) return ack({ error: 'not_in_file' });
      await Collaborator.updateOne({ _id: `${socket.id}:${userId}` }, { $set: { followingUserId: leaderId } });
      ack({ ok: true });
    });
    socket.on('follow:stop', async () => {
      await Collaborator.updateOne({ _id: `${socket.id}:${userId}` }, { $unset: { followingUserId: 1 } });
    });

    socket.on('disconnect', async () => {
      if (!fileId) return;
      await redis.hdel(`cursors:${fileId}`, userId);
      await Collaborator.deleteOne({ _id: `${socket.id}:${userId}` });
      nsp.to(`file:${fileId}`).emit('collab:left', { userId });
    });
  });
}
function pickColor(uid: string){ const palette = ['#e91e63','#3f51b5','#009688','#ff9800','#9c27b0']; let h=0; for (const c of uid) h = (h*31+c.charCodeAt(0))|0; return palette[Math.abs(h)%palette.length]; }

