// src/hooks/useCursors.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/cursors',{auth:{token},transports:['websocket']}); return sock; }

type Cursor = { userId:string; line:number; col:number; selStart?:any; selEnd?:any; viewportTop:number; viewportBottom:number; color?:string; displayName?:string };
export function useCursors(fileId:string, token:string) {
  const [cursors, setCursors] = useState<Map<string, Cursor>>(new Map());
  const [followLeader, setFollowLeader] = useState<string | null>(null);
  const followCallbackRef = useRef<((vt:number,vb:number)=>void) | null>(null);
  const lastEmitRef = useRef(0);

  useEffect(() => {
    const socket = getSock(token);
    const join = () => socket.emit('file:join', { fileId }, (res:any) => {
      if (res.error) return;
      const next = new Map<string, Cursor>();
      for (const [uid, c] of Object.entries<any>(res.cursors)) next.set(uid, c);
      for (const r of res.roster) { const c = next.get(r.userId) ?? { userId: r.userId, line:0, col:0, viewportTop:0, viewportBottom:0 } as Cursor; c.color = r.color; c.displayName = r.displayName; next.set(r.userId, c); }
      setCursors(next);
    });
    const onChange = (c: Cursor) => setCursors(prev => { const n = new Map(prev); const cur = n.get(c.userId) ?? {} as Cursor; n.set(c.userId, { ...cur, ...c }); return n; });
    const onJoined = ({ userId, displayName, color }:any) => setCursors(p => { const n = new Map(p); const cur = n.get(userId) ?? { userId, line:0, col:0, viewportTop:0, viewportBottom:0 }; n.set(userId, { ...cur, displayName, color }); return n; });
    const onLeft = ({ userId }:any) => setCursors(p => { const n = new Map(p); n.delete(userId); return n; });
    const onFollow = ({ leaderId, viewportTop, viewportBottom }:any) => { if (followCallbackRef.current && leaderId === followLeader) followCallbackRef.current(viewportTop, viewportBottom); };
    socket.on('connect', join);
    socket.on('cursor:change', onChange); socket.on('collab:joined', onJoined); socket.on('collab:left', onLeft); socket.on('follow:viewport', onFollow);
    if (socket.connected) join();
    return () => { socket.off('connect', join); socket.off('cursor:change', onChange); socket.off('collab:joined', onJoined); socket.off('collab:left', onLeft); socket.off('follow:viewport', onFollow); };
  }, [fileId, token, followLeader]);

  const reportCursor = useCallback((c: Omit<Cursor, 'userId'>) => {
    const now = performance.now();
    if (now - lastEmitRef.current < 16) return; // 60Hz local cap; server throttles to 30Hz
    lastEmitRef.current = now;
    getSock(token).emit('cursor:move', c);
  }, [token]);

  const startFollow = useCallback((leaderId:string, onViewport:(vt:number,vb:number)=>void) => {
    followCallbackRef.current = onViewport;
    setFollowLeader(leaderId);
    getSock(token).emit('follow:start', { leaderId }, () => {});
  }, [token]);
  const stopFollow = useCallback(() => { followCallbackRef.current = null; setFollowLeader(null); getSock(token).emit('follow:stop'); }, [token]);

  return { cursors: [...cursors.values()], reportCursor, startFollow, stopFollow, followLeader };
}

