-- builds on sock-002 messages
ALTER TABLE messages ADD COLUMN parent_id BIGINT REFERENCES messages(id);
ALTER TABLE messages ADD COLUMN replies_count INT NOT NULL DEFAULT 0;
ALTER TABLE messages ADD COLUMN last_reply_at TIMESTAMPTZ;
ALTER TABLE messages ADD COLUMN tsv TSVECTOR;

CREATE INDEX ON messages USING GIN (tsv);
CREATE INDEX ON messages (parent_id, id) WHERE parent_id IS NOT NULL;

CREATE OR REPLACE FUNCTION msg_tsv() RETURNS TRIGGER AS $$
BEGIN NEW.tsv := to_tsvector('english', NEW.body); RETURN NEW; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER messages_tsv BEFORE INSERT OR UPDATE OF body ON messages FOR EACH ROW EXECUTE FUNCTION msg_tsv();

CREATE TABLE mentions (
  id BIGSERIAL PK,
  message_id BIGINT NOT NULL REFERENCES messages(id),
  mentioned_user_id BIGINT NOT NULL,
  notified BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (message_id, mentioned_user_id)
);
CREATE INDEX ON mentions (mentioned_user_id, notified);

CREATE OR REPLACE FUNCTION update_parent_reply_counter() RETURNS TRIGGER AS $$
BEGIN
  IF TG_OP = 'INSERT' AND NEW.parent_id IS NOT NULL THEN
    UPDATE messages SET replies_count = replies_count + 1, last_reply_at = NEW.created_at WHERE id = NEW.parent_id;
    PERFORM pg_notify('msg_parent_' || NEW.parent_id, NEW.id::text);
  ELSIF TG_OP = 'UPDATE' AND OLD.deleted_at IS NULL AND NEW.deleted_at IS NOT NULL AND NEW.parent_id IS NOT NULL THEN
    UPDATE messages SET replies_count = replies_count - 1 WHERE id = NEW.parent_id;
  END IF;
  RETURN NEW;
END; $$ LANGUAGE plpgsql;
CREATE TRIGGER messages_reply_counter AFTER INSERT OR UPDATE OF deleted_at ON messages FOR EACH ROW EXECUTE FUNCTION update_parent_reply_counter();

