// src/routes/messagesThreads.ts
import { Router } from 'express';
import { pool } from '../infra/pg';
import { enqueueNotification } from '../services/notificationService'; // from sock-008
export const threadsRouter = Router();
threadsRouter.post('/messages', async (req, res) => {
  const { channelId, parentId, clientMsgId, body } = req.body;
  const userId = req.user!.id;
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      `INSERT INTO messages(channel_id,parent_id,author_id,client_msg_id,body) VALUES ($1,$2,$3,$4,$5)
       ON CONFLICT (channel_id,client_msg_id) DO UPDATE SET body = messages.body RETURNING id, created_at`,
      [channelId, parentId ?? null, userId, clientMsgId, body],
    );
    const msgId = rows[0].id;
    const mentions = parseMentions(body); // returns array of userIds
    for (const mid of mentions) {
      await client.query('INSERT INTO mentions(message_id, mentioned_user_id) VALUES ($1,$2) ON CONFLICT DO NOTHING', [msgId, mid]);
    }
    await client.query('COMMIT');
    for (const mid of mentions) {
      await enqueueNotification(String(mid), { type: 'mention', targetType: 'message', targetId: String(msgId), actorId: String(userId), body: `${req.user!.name} mentioned you` });
    }
    res.json({ id: String(msgId), createdAt: rows[0].created_at });
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
});

