// add LISTEN on msg_parent_* and emit parent:updated to channel room
import { Client } from 'pg';
import { sub, pool as poolCore } from '../infra/redis';
const pgListen = new Client({ connectionString: process.env.DATABASE_URL });
export async function startThreadListener() {
  await pgListen.connect();
  await pgListen.query("SELECT 'noop'"); // we'll LISTEN dynamically as threads are opened
}

export function extendChatNamespaceWithThreads(nsp: any) {
  nsp.on('connection', (socket: any) => {
    socket.on('thread:open', async ({ parentId }, ack: any) => {
      await socket.join(`thread:${parentId}`);
      await pgListen.query(`LISTEN msg_parent_${parentId}`);
      const { rows } = await pool.query('SELECT id,author_id,body,created_at FROM messages WHERE parent_id=$1 AND deleted_at IS NULL ORDER BY id ASC LIMIT 500', [parentId]);
      ack({ replies: rows });
    });
    socket.on('thread:close', async ({ parentId }) => {
      await socket.leave(`thread:${parentId}`);
      // we don't UNLISTEN — other sockets may still be in this thread
    });
  });
  pgListen.on('notification', async (n) => {
    if (!n.channel.startsWith('msg_parent_')) return;
    const parentId = n.channel.slice('msg_parent_'.length);
    const { rows } = await pool.query('SELECT id,channel_id,parent_id,author_id,body,created_at FROM messages WHERE id=$1', [n.payload]);
    if (rows[0]) {
      nsp.to(`thread:${parentId}`).emit('reply:new', rows[0]);
      // update parent badge in channel
      const { rows: pr } = await pool.query('SELECT channel_id, replies_count, last_reply_at FROM messages WHERE id=$1', [parentId]);
      if (pr[0]) nsp.to(`chan:${pr[0].channel_id}`).emit('parent:updated', { parentId, repliesCount: pr[0].replies_count, lastReplyAt: pr[0].last_reply_at });
    }
  });
}

