export const searchRouter = Router();
searchRouter.get('/search', async (req, res) => {
  const q = String(req.query.q || '').slice(0, 200);
  const tsQuery = q.split(/\s+/).filter(Boolean).map(t => t.replace(/[^\w]/g,'') + ':*').join(' & ');
  if (!tsQuery) return res.json({ results: [] });
  const { rows } = await pool.query(
    `SELECT m.id, m.channel_id, m.body, m.created_at, ts_rank(m.tsv, q) AS rank
     FROM messages m, to_tsquery('english', $1) q
     WHERE m.tsv @@ q AND m.deleted_at IS NULL AND m.channel_id = ANY($2::bigint[])
     ORDER BY rank DESC LIMIT 50`,
    [tsQuery, await accessibleChannelIds(req.user!.id)],
  );
  res.json({ results: rows });
});

function parseMentions(body: string): number[] {
  // simplified: @<id> or @name resolved via lookup table; here assume @<numeric>
  return Array.from(body.matchAll(/@(\d+)/g)).map(m => Number(m[1]));
}

