// src/workers/statusStream.ts
import mongoose from 'mongoose';
import { Status } from '../models/Status';
import { Alert } from '../models/Alert';
import { redis } from '../infra/redis';
export async function runStatusStream() {
  let resume = await redis.get('status:resume'); let token = resume ? JSON.parse(resume) : undefined;
  while (true) {
    try {
      const stream = Status.watch([{ $match: { operationType: { $in: ['insert','update','replace'] } } }], { fullDocument: 'updateLookup', resumeAfter: token });
      for await (const c of stream) {
        token = c._id as any; await redis.set('status:resume', JSON.stringify(token));
        const doc = (c as any).fullDocument; if (!doc) continue;
        await redis.publish(`status:tile:${doc.service}:${doc.region}`, JSON.stringify(doc));
      }
    } catch (e) { await new Promise(r=>setTimeout(r,500)); }
  }
}
export async function runAlertStream(io: any) {
  const stream = Alert.watch([{ $match: { operationType: 'insert' } }], { fullDocument: 'updateLookup' });
  for await (const c of stream) {
    const a = (c as any).fullDocument;
    io.of('/status').to(`board:default`).emit('alert:new', a);
  }
}
export async function ingestStatus(service:string, region:string, patch:any) {
  const id = `${service}:${region}`;
  const prev = await Status.findById(id).lean();
  const isChange = prev && prev.status !== patch.status;
  const inc = isChange ? 1 : 0;
  const doc = await Status.findOneAndUpdate({ _id: id }, {
    $set: { ...patch, service, region, lastChangedAt: isChange ? new Date() : prev?.lastChangedAt ?? new Date() },
    $inc: { transitionsLast30s: inc },
  }, { upsert: true, new: true });
  if (doc.transitionsLast30s > 3) {
    await Status.updateOne({_id:id}, { $set: { status: 'flapping' } });
  }
  // reset transition counter older than 30s — simple background sweeper not shown
  if (isChange && (patch.status === 'down' || patch.status === 'degraded')) {
    await Alert.create({ service, region, severity: patch.status === 'down' ? 'crit' : 'warn', message: `${service}/${region} → ${patch.status}` });
  }
}

