// src/matchmaker/loop.ts
import { redis } from '../infra/redis';
import { Party } from '../models/Party';
import { MatchAssignment } from '../models/MatchAssignment';
import { v4 as uuid } from 'uuid';
import { io } from '../server';
const TEAM_SIZE = 5;

export async function matchmakerTick(region:string, mode:string) {
  // pull oldest 50 candidates
  const candidates = await redis.zrange(`mm:${region}:${mode}`, 0, 49, 'WITHSCORES');
  // candidates: [partyId, score, partyId, score, ...]
  const parsed: { partyId: string; joinedAt: number }[] = [];
  for (let i = 0; i < candidates.length; i += 2) parsed.push({ partyId: candidates[i], joinedAt: Number(candidates[i+1]) });
  if (parsed.length < 2) return;
  const parties = await Party.find({ _id: { $in: parsed.map(p => p.partyId) }, status: 'queued' }).lean();
  const byMMR = parties.sort((a:any,b:any) => (a.avgMMR ?? 1500) - (b.avgMMR ?? 1500));
  // greedy pair by adjacent MMR until we hit TEAM_SIZE per side
  const groupA: any[] = []; const groupB: any[] = [];
  for (const p of byMMR) {
    const target = groupA.length <= groupB.length ? groupA : groupB;
    const targetSize = target.reduce((s,x)=>s+x.memberIds.length, 0);
    if (targetSize + p.memberIds.length <= TEAM_SIZE) target.push(p);
    if (groupA.reduce((s,x)=>s+x.memberIds.length, 0) === TEAM_SIZE && groupB.reduce((s,x)=>s+x.memberIds.length, 0) === TEAM_SIZE) break;
  }
  if (groupA.reduce((s,x)=>s+x.memberIds.length, 0) !== TEAM_SIZE || groupB.reduce((s,x)=>s+x.memberIds.length, 0) !== TEAM_SIZE) return;
  const matched = [...groupA, ...groupB];
  const playerIds: string[] = matched.flatMap(p => p.memberIds);
  // lock players (SETNX)
  const lockOk = await Promise.all(playerIds.map(uid => redis.set(`mm:lock:${uid}`, '1', 'NX', 'EX', 30)));
  if (lockOk.some(r => r !== 'OK')) { /* release the ones we got */ for (let i=0; i<lockOk.length; i++) if (lockOk[i]==='OK') await redis.del(`mm:lock:${playerIds[i]}`); return; }
  // remove from queue
  await redis.zrem(`mm:${region}:${mode}`, ...matched.map(p => p._id));
  // create assignment
  const id = uuid();
  await MatchAssignment.create({ _id: id, region, mode, partyIds: matched.map(p => p._id), playerIds, acceptances: {}, expiresAt: new Date(Date.now() + 15_000) });
  for (const uid of playerIds) io.of('/lobby').to(`user:${uid}:lobby`).emit('match:found', { matchId: id, acceptUntil: Date.now() + 15_000 });
}

// src/socket/lobby.namespace.ts
import { Namespace } from 'socket.io';
import { Party } from '../models/Party';
import { MatchAssignment } from '../models/MatchAssignment';
import { redis } from '../infra/redis';

export function registerLobbyNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', async (socket) => {
    const userId = socket.data.user.id;
    await socket.join(`user:${userId}:lobby`);
    const party = await Party.findOne({ memberIds: userId });
    if (party) await socket.join(`party:${party._id}`);

    socket.on('queue:start', async ({ mode, region }, ack) => {
      const p = await Party.findOneAndUpdate({ leaderId: userId, status: 'idle' }, { $set: { status: 'queued', queuedAt: new Date(), mode, region } }, { new: true });
      if (!p) return ack({ error: 'not_leader_or_busy' });
      await redis.zadd(`mm:${region}:${mode}`, Date.now(), String(p._id));
      nsp.to(`party:${p._id}`).emit('queue:started', { party: p });
      ack({ ok: true });
    });

    socket.on('queue:cancel', async (_, ack) => {
      const p = await Party.findOneAndUpdate({ leaderId: userId, status: 'queued' }, { $set: { status: 'idle' } }, { new: true });
      if (!p) return ack({ error: 'no_queue' });
      await redis.zrem(`mm:${p.region}:${p.mode}`, String(p._id));
      nsp.to(`party:${p._id}`).emit('queue:cancelled');
      ack({ ok: true });
    });

    socket.on('match:accept', async ({ matchId }, ack) => {
      const m = await MatchAssignment.findOneAndUpdate({ _id: matchId, status: 'pending', playerIds: userId }, { $set: { [`acceptances.${userId}`]: true } }, { new: true });
      if (!m) return ack({ error: 'invalid' });
      const acceptedCount = m.acceptances ? Object.values(Object.fromEntries(m.acceptances as any)).filter(Boolean).length : 0;
      if (acceptedCount === m.playerIds.length) {
        await MatchAssignment.updateOne({ _id: matchId, status: 'pending' }, { $set: { status: 'accepted' } });
        // provision game server, then notify
        const matchInfo = await provisionGameServer(m);
        for (const uid of m.playerIds) nsp.to(`user:${uid}:lobby`).emit('match:start', matchInfo);
        await Party.updateMany({ _id: { $in: m.partyIds } }, { $set: { status: 'in_match' } });
      }
      ack({ ok: true });
    });

    socket.on('match:decline', async ({ matchId }) => {
      const m = await MatchAssignment.findOneAndUpdate({ _id: matchId, status: 'pending' }, { $set: { status: 'cancelled' } }, { new: true });
      if (!m) return;
      for (const uid of m.playerIds) { await redis.del(`mm:lock:${uid}`); nsp.to(`user:${uid}:lobby`).emit('match:declined', { matchId, by: userId }); }
      // requeue accepters
      await Party.updateMany({ _id: { $in: m.partyIds }, status: 'queued' /* defensive */ }, { $set: { status: 'queued' } });
      for (const pid of m.partyIds) { const p = await Party.findById(pid).lean(); if (p) await redis.zadd(`mm:${p.region}:${p.mode}`, Date.now(), String(pid)); }
    });
  });
}
async function provisionGameServer(m:any){ return { matchId: m._id, host: 'game-1.region', port: 8888, token: 'sigh' }; }

