// src/socket/market.namespace.ts
import { Namespace } from 'socket.io';
import { redis, sub } from '../infra/redis';

export function registerMarketNamespace(nsp: Namespace) {
  nsp.use(authMw);
  sub.psubscribe('mkt:delta:*'); sub.psubscribe('mkt:snap:*');
  sub.on('pmessage', (_p, ch, payload) => {
    const [, type, sym] = ch.split(':');
    if (type === 'delta') nsp.to(`sym:${sym}`).emit('delta', JSON.parse(payload));
    else nsp.to(`sym:${sym}`).emit('snapshot', JSON.parse(payload));
  });
  nsp.on('connection', (socket) => {
    socket.on('sym:subscribe', async ({ symbols }, ack) => {
      for (const s of symbols) await socket.join(`sym:${s}`);
      // bootstrap snapshot per symbol
      const snaps:any[] = [];
      for (const s of symbols) {
        const seq = Number(await redis.get(`book:seq:${s}`) ?? 0);
        const bids = await redis.zrange(`book:bids:${s}`, 0, 99, 'WITHSCORES');
        const asks = await redis.zrange(`book:asks:${s}`, 0, 99, 'WITHSCORES');
        snaps.push({ sym: s, seq, bids: zipPS(bids), asks: zipPS(asks) });
      }
      ack({ snapshots: snaps });
    });
    socket.on('resnapshot', async ({ sym }, ack) => {
      const seq = Number(await redis.get(`book:seq:${sym}`) ?? 0);
      const bids = await redis.zrange(`book:bids:${sym}`, 0, 99, 'WITHSCORES');
      const asks = await redis.zrange(`book:asks:${sym}`, 0, 99, 'WITHSCORES');
      ack({ sym, seq, bids: zipPS(bids), asks: zipPS(asks) });
    });
  });
}
function zipPS(arr:string[]){ const out:[number,number][]=[]; for (let i=0;i<arr.length;i+=2) out.push([Number(arr[i+1]),Number(arr[i])]); return out; }

