// src/hooks/useOrderBook.ts
import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(token:string){ if(sock) return sock; sock = io('/market',{auth:{token},transports:['websocket']}); return sock; }
export function useOrderBook(sym:string, token:string) {
  const [book, setBook] = useState<{bids: Map<number,number>; asks: Map<number,number>}>({ bids: new Map(), asks: new Map() });
  const seqRef = useRef(0);
  useEffect(() => {
    const socket = getSock(token);
    const sub = () => socket.emit('sym:subscribe', { symbols: [sym] }, (res:any) => {
      const s = res.snapshots.find((x:any)=>x.sym===sym); if (!s) return;
      seqRef.current = s.seq;
      setBook({ bids: new Map(s.bids), asks: new Map(s.asks) });
    });
    const onSnap = (s:any) => { if (s.sym !== sym) return; seqRef.current = s.seq; setBook({ bids: new Map(s.bids), asks: new Map(s.asks) }); };
    const onDelta = (d:any) => {
      if (d.sym !== sym) return;
      if (d.seq !== seqRef.current + 1) {
        // gap! request resnapshot
        socket.emit('resnapshot', { sym }, (res:any) => onSnap(res));
        return;
      }
      seqRef.current = d.seq;
      setBook(prev => {
        const side = d.side === 'b' ? new Map(prev.bids) : new Map(prev.asks);
        if (d.size === 0) side.delete(d.price); else side.set(d.price, d.size);
        return d.side === 'b' ? { ...prev, bids: side } : { ...prev, asks: side };
      });
    };
    socket.on('connect', sub); socket.on('snapshot', onSnap); socket.on('delta', onDelta);
    if (socket.connected) sub();
    return () => { socket.emit('sym:unsubscribe', { symbols: [sym] }); socket.off('connect', sub); socket.off('snapshot', onSnap); socket.off('delta', onDelta); };
  }, [sym, token]);
  return { book };
}

