// extends sock-006 presence ns
import { ActiveDoc } from '../models/ActiveDoc';
import { Doc } from '../models/Doc';
import { redis } from '../infra/redis';
export function registerDocPresence(nsp: any) {
  nsp.on('connection', (socket: any) => {
    const userId = socket.data.user.id;
    socket.on('doc:active', async ({ docId, tabId }, ack: any) => {
      const doc = await Doc.findById(docId, { workspaceId: 1 }).lean();
      if (!doc) return ack({ error: 'no_doc' });
      const _id = `${userId}:${docId}:${tabId}`;
      await ActiveDoc.updateOne({ _id }, { $set: { userId, docId, workspaceId: doc.workspaceId, tabId, lastSeenAt: new Date() } }, { upsert: true });
      await redis.publish('doc:presence:change', JSON.stringify({ userId, docId, workspaceId: doc.workspaceId, in: true }));
      ack?.({ ok: true });
    });
    socket.on('doc:inactive', async ({ docId, tabId }) => {
      await ActiveDoc.deleteOne({ _id: `${userId}:${docId}:${tabId}` });
      const remaining = await ActiveDoc.countDocuments({ userId, docId });
      if (remaining === 0) await redis.publish('doc:presence:change', JSON.stringify({ userId, docId, in: false }));
    });
    socket.on('doc:hb', async ({ docId, tabId }) => {
      await ActiveDoc.updateOne({ _id: `${userId}:${docId}:${tabId}` }, { $set: { lastSeenAt: new Date() } });
    });
    socket.on('disconnect', async () => {
      const docs = await ActiveDoc.find({ userId }).lean();
      await ActiveDoc.deleteMany({ userId });
      for (const d of docs) await redis.publish('doc:presence:change', JSON.stringify({ userId, docId: d.docId, in: false }));
    });
  });
}

