// src/socket/annotationsExtended.ts
import { Namespace } from 'socket.io';
import { Annotation } from '../models/Annotation';
import { Reply } from '../models/Reply';
import { redis } from '../infra/redis';
import { enqueueNotification } from '../services/notificationService';

export function extendAnnotationsNamespace(nsp: Namespace) {
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('anno:thread:open', async ({ annoId }, ack) => {
      await socket.join(`anno:${annoId}`);
      const [anno, replies] = await Promise.all([
        Annotation.findById(annoId).lean(),
        Reply.find({ annotationId: annoId }).sort({ createdAt: 1 }).limit(200).lean(),
      ]);
      if (!anno) return ack({ error: 'no_anno' });
      const counts = aggregateCounts(anno);
      ack({ replies, counts, myReactions: myReactionsFor(anno, userId) });
    });

    socket.on('anno:react', async ({ annoId, emoji, add }, ack) => {
      const op = add
        ? { $addToSet: { 'reactions.$[r].userIds': userId } }
        : { $pull: { 'reactions.$[r].userIds': userId } };
      let res = await Annotation.findOneAndUpdate(
        { _id: annoId, 'reactions.emoji': emoji }, op, { new: true, arrayFilters: [{ 'r.emoji': emoji }] },
      );
      if (!res && add) {
        res = await Annotation.findOneAndUpdate({ _id: annoId }, { $push: { reactions: { emoji, userIds: [userId] } } }, { new: true });
      }
      if (!res) return ack({ error: 'no_anno' });
      const counts = aggregateCounts(res);
      // hot counter mirror
      const pipe = redis.pipeline();
      for (const [e, c] of Object.entries(counts)) pipe.hset(`anno:react:${annoId}`, e, c);
      pipe.expire(`anno:react:${annoId}`, 300);
      await pipe.exec();
      nsp.to(`anno:${annoId}`).emit('anno:reaction:update', { annoId, counts });
      ack({ counts });
    });

    socket.on('anno:reply', async ({ annoId, body, clientId }, ack) => {
      const anno = await Annotation.findById(annoId);
      if (!anno || anno.deletedAt) return ack({ error: 'no_anno_or_deleted' });
      const reply = await Reply.create({ _id: clientId, annotationId: annoId, authorId: userId, body });
      await Annotation.updateOne({ _id: annoId }, { $inc: { replyCount: 1 } });
      nsp.to(`anno:${annoId}`).emit('anno:reply:new', reply.toObject());
      // notify annotation author if not self
      if (String(anno.authorId) !== userId) {
        await enqueueNotification(String(anno.authorId), { type: 'anno_reply', targetType: 'annotation', targetId: annoId, actorId: userId, body: `New reply on your comment` });
      }
      ack({ reply: reply.toObject() });
    });
  });
}
function aggregateCounts(anno:any){ return Object.fromEntries((anno.reactions||[]).map((r:any)=>[r.emoji, r.userIds.length])); }
function myReactionsFor(anno:any, userId:string){ return (anno.reactions||[]).filter((r:any)=>r.userIds.includes(userId)).map((r:any)=>r.emoji); }

