// src/hooks/useAnnoThread.ts
import { useEffect, useState, useCallback } from 'react';
import { v4 as uuid } from 'uuid';
import { getSock } from '../socket/annotationsSocket';
export function useAnnoThread(annoId:string, token:string) {
  const [replies, setReplies] = useState<any[]>([]);
  const [counts, setCounts] = useState<Record<string,number>>({});
  const [mine, setMine] = useState<string[]>([]);
  useEffect(() => {
    const socket = getSock(token);
    const open = () => socket.emit('anno:thread:open', { annoId }, (res:any) => { if (res.error) return; setReplies(res.replies); setCounts(res.counts); setMine(res.myReactions); });
    const onCounts = (e:any) => { if (e.annoId !== annoId) return; setCounts(e.counts); };
    const onReply = (r:any) => setReplies(p => p.find(x => x._id === r._id) ? p : [...p, r]);
    socket.on('connect', open); socket.on('anno:reaction:update', onCounts); socket.on('anno:reply:new', onReply);
    if (socket.connected) open();
    return () => { socket.off('connect', open); socket.off('anno:reaction:update', onCounts); socket.off('anno:reply:new', onReply); };
  }, [annoId, token]);
  const react = useCallback((emoji:string) => {
    const add = !mine.includes(emoji);
    setMine(prev => add ? [...prev, emoji] : prev.filter(e => e !== emoji));
    setCounts(prev => ({ ...prev, [emoji]: (prev[emoji] ?? 0) + (add ? 1 : -1) }));
    getSock(token).emit('anno:react', { annoId, emoji, add }, (res:any) => { if (res.counts) setCounts(res.counts); });
  }, [mine, annoId, token]);
  const reply = useCallback((body:string) => {
    const clientId = uuid();
    const optimistic = { _id: clientId, annotationId: annoId, authorId: 'me', body, createdAt: new Date().toISOString(), pending: true };
    setReplies(p => [...p, optimistic]);
    getSock(token).emit('anno:reply', { annoId, body, clientId }, (res:any) => {
      if (res.error) setReplies(p => p.filter(x => x._id !== clientId));
      else setReplies(p => p.map(x => x._id === clientId ? res.reply : x));
    });
  }, [annoId, token]);
  return { replies, counts, mine, react, reply };
}

