// src/services/notifRouter.ts
import { pool } from '../infra/pg';
import { Prefs } from '../models/Prefs';
import { Queue } from 'bullmq';
import { redis } from '../infra/redis';
import { DateTime } from 'luxon';
const Qs = { inApp: new Queue('ch:inApp',{connection:redis}), email: new Queue('ch:email',{connection:redis}), sms: new Queue('ch:sms',{connection:redis}), push: new Queue('ch:push',{connection:redis}), slack: new Queue('ch:slack',{connection:redis}) };

export async function route(notifId: string) {
  const { rows } = await pool.query('SELECT id, user_id, urgency, type FROM notifications WHERE id=$1', [notifId]);
  if (!rows[0]) return;
  const n = rows[0];
  const prefs = await Prefs.findById(String(n.user_id)).lean();
  if (!prefs) return; // default: just inApp
  const inDnd = isInDnd(prefs);
  const allowedByRule = (prefs.rules?.find((r:any) => r.urgency === n.urgency)?.channels) ?? ['inApp','push'];
  const channels: string[] = [];
  for (const ch of allowedByRule) {
    if (!(prefs.channels as any)[ch === 'slack' ? 'slack' : ch]?.enabled && ch !== 'inApp') continue;
    if (inDnd && n.urgency !== 'urgent') continue;
    if (await capExceeded(n.user_id, ch, prefs.caps?.perHour ?? 30)) continue;
    channels.push(ch);
  }
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    for (const ch of channels) {
      await client.query('INSERT INTO notification_dispatches(notification_id, channel, status) VALUES ($1,$2,$3) ON CONFLICT DO NOTHING', [notifId, ch, 'enqueued']);
    }
    await client.query('COMMIT');
    for (const ch of channels) await (Qs as any)[ch].add('dispatch', { notifId, userId: n.user_id });
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
}
function isInDnd(p:any){ if (!p.dnd?.start) return false; const now = DateTime.now().setZone(p.timezone || 'UTC'); if (!p.dnd.days?.includes(now.weekday%7)) return false; const cur = now.toFormat('HH:mm'); return p.dnd.start <= p.dnd.end ? cur >= p.dnd.start && cur <= p.dnd.end : cur >= p.dnd.start || cur <= p.dnd.end; }
async function capExceeded(userId:any, ch:string, cap:number){ const k = `notif:cap:${userId}:${ch}:${new Date().toISOString().slice(0,13)}`; const c = await redis.incr(k); if (c===1) await redis.expire(k, 3600); return c > cap; }

// per-channel worker example: in-app
import { Worker } from 'bullmq';
import { io } from '../server';
export function startInAppWorker() {
  new Worker('ch:inApp', async (job: any) => {
    const { notifId, userId } = job.data;
    const { rows } = await pool.query('SELECT id, type, body, created_at FROM notifications WHERE id=$1', [notifId]);
    if (!rows[0]) return;
    const room = `user:${userId}`;
    const sockets = await io.of('/notifications').in(room).fetchSockets();
    if (sockets.length === 0) { await pool.query("UPDATE notification_dispatches SET status='no_session', completed_at=now() WHERE notification_id=$1 AND channel='inApp'", [notifId]); return; }
    io.of('/notifications').to(room).emit('notif:new', { id: String(rows[0].id), type: rows[0].type, body: rows[0].body, createdAt: rows[0].created_at });
    await pool.query("UPDATE notification_dispatches SET status='delivered', completed_at=now() WHERE notification_id=$1 AND channel='inApp'", [notifId]);
  }, { connection: redis });
}

