export async function ingestSample(s: { patientId:string; metric:string; ts:number; value:number; teamId:string; raw?:Buffer }) {
  await Sample.create({ patientId: s.patientId, metric: s.metric, ts: new Date(s.ts), value: s.value, raw: s.raw });
  io.of('/patient').to(`patient:${s.patientId}`).emit('sample', s);
  const score = scoreAnomaly(s);
  if (score > 0.85) {
    const a = await Anomaly.create({ patientId: s.patientId, metric: s.metric, ts: new Date(s.ts), score, type: 'arrhythmia' });
    const shift = await Shift.findOne({ teamId: s.teamId, startsAt: { $lte: new Date() }, endsAt: { $gt: new Date() } }).lean();
    if (shift) io.of('/patient').to(`user:${shift.clinicianId}:alerts`).emit('anomaly', { ...a.toObject() });
  }
}

