// src/socket/webinar.namespace.ts
import { Namespace } from 'socket.io';
import { pool } from '../infra/pg';

export function registerWebinarNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('event:join', async ({ eventId }, ack) => {
      const role = await getOrAssignRole(eventId, userId);
      if (!role) return ack({ error: 'forbidden' });
      await socket.join(`event:${eventId}`);
      if (role === 'host' || role === 'co-host') await socket.join(`event:${eventId}:hosts`);
      const state = await loadEventState(eventId);
      ack({ role, state });
    });
    socket.on('hand:raise', async ({ eventId }, ack) => {
      // rate-limit on socket: handled by middleware
      await pool.query(`UPDATE event_participants SET hand_raised_at=now() WHERE event_id=$1 AND user_id=$2 AND role='viewer' AND hand_raised_at IS NULL`, [eventId, userId]);
      nsp.to(`event:${eventId}:hosts`).emit('hand:raised', { userId });
      ack({ ok: true });
    });
    socket.on('promote', async ({ eventId, targetId }, ack) => {
      if (!await isHost(eventId, userId)) return ack({ error: 'forbidden' });
      const r = await pool.query(`UPDATE event_participants SET role='speaker', hand_raised_at=NULL WHERE event_id=$1 AND user_id=$2 AND role='viewer' RETURNING role`, [eventId, targetId]);
      if (r.rowCount === 0) return ack({ error: 'not_promotable' });
      await pool.query('INSERT INTO event_actions(event_id, actor_id, target_id, action) VALUES ($1,$2,$3,$4)', [eventId, userId, targetId, 'promote']);
      nsp.to(`event:${eventId}`).emit('role:changed', { userId: targetId, role: 'speaker' });
      ack({ ok: true });
    });
    socket.on('mute:all', async ({ eventId }, ack) => {
      if (!await isHost(eventId, userId)) return ack({ error: 'forbidden' });
      await pool.query('BEGIN');
      await pool.query('INSERT INTO event_actions(event_id, actor_id, action) VALUES ($1,$2,$3)', [eventId, userId, 'mute_all']);
      // signal speakers to mute via SFU; pause producers
      await pool.query('COMMIT');
      nsp.to(`event:${eventId}`).emit('muted:all', { by: userId });
      ack({ ok: true });
    });
    socket.on('kick', async ({ eventId, targetId }, ack) => {
      if (!await isHost(eventId, userId)) return ack({ error: 'forbidden' });
      await pool.query(`UPDATE event_participants SET left_at=now(), role='viewer' WHERE event_id=$1 AND user_id=$2`, [eventId, targetId]);
      await pool.query('INSERT INTO event_actions(event_id, actor_id, target_id, action) VALUES ($1,$2,$3,$4)', [eventId, userId, targetId, 'kick']);
      const sockets = await nsp.in(`event:${eventId}`).fetchSockets();
      for (const s of sockets) if (s.data.user.id === targetId) s.disconnect(true);
      ack({ ok: true });
    });
  });
}

