// src/socket/wizardForms.namespace.ts
import { Namespace } from 'socket.io';
import { Application } from '../models/Application';
import { redis } from '../infra/redis';
import { validateApp, computeBranch } from '../validation/engine';

export function registerWizardNamespace(nsp: Namespace) {
  nsp.use(authMw);
  nsp.on('connection', (socket) => {
    const userId = socket.data.user.id;
    socket.on('app:open', async ({ appId }, ack) => {
      const app = await Application.findById(appId).lean();
      if (!app || !app.collaboratorIds.includes(userId)) return ack({ error: 'forbidden' });
      await socket.join(`app:${appId}`);
      const locks = await redis.hgetall(`app:locks:${appId}`);
      ack({ app, locks });
    });
    socket.on('step:lock', async ({ appId, stepId }, ack) => {
      const ok = await redis.hsetnx(`app:locks:${appId}`, stepId, userId);
      if (!ok) return ack({ ok: false, lockedBy: await redis.hget(`app:locks:${appId}`, stepId) });
      await redis.expire(`app:locks:${appId}`, 600);
      nsp.to(`app:${appId}`).emit('step:locked', { stepId, userId });
      ack({ ok: true });
    });
    socket.on('step:unlock', async ({ appId, stepId }) => {
      const owner = await redis.hget(`app:locks:${appId}`, stepId);
      if (owner === userId) { await redis.hdel(`app:locks:${appId}`, stepId); nsp.to(`app:${appId}`).emit('step:unlocked', { stepId }); }
    });
    socket.on('step:submit', async ({ appId, stepId, fields, expectedVersion }, ack) => {
      const owner = await redis.hget(`app:locks:${appId}`, stepId);
      if (owner !== userId) return ack({ error: 'not_locked' });
      const app = await Application.findOneAndUpdate(
        { _id: appId, version: expectedVersion },
        { $set: { [`steps.${stepId}`]: { fields, completedBy: userId, completedAt: new Date() } }, $inc: { version: 1 } },
        { new: true },
      );
      if (!app) return ack({ error: 'version_conflict' });
      // recompute branch + validation
      const newBranch = computeBranch(app.steps as any, app.templateId);
      if (newBranch !== app.branchKey) {
        // invalidate future steps not in new branch
        const updated = await Application.findByIdAndUpdate(appId, { $set: { branchKey: newBranch } }, { new: true });
        nsp.to(`app:${appId}`).emit('branch:changed', { branchKey: newBranch });
      }
      const errors = await validateApp(app);
      nsp.to(`app:${appId}`).emit('step:updated', { stepId, fields, version: app.version, by: userId });
      nsp.to(`app:${appId}`).emit('validation:errors', { errors });
      // auto-release lock on submit
      await redis.hdel(`app:locks:${appId}`, stepId);
      nsp.to(`app:${appId}`).emit('step:unlocked', { stepId });
      ack({ ok: true, version: app.version, errors });
    });
    socket.on('disconnect', async () => { /* release all locks held by this user — scan their locks via reverse index */ });
  });
}

