    const onUpdated = ({stepId,fields,version}:any) => setApp((a:any) => a ? { ...a, steps: { ...a.steps, [stepId]: { ...(a.steps?.[stepId] ?? {}), fields } }, version } : a);
    const onBranch = ({branchKey}:any) => setApp((a:any) => a ? { ...a, branchKey } : a);
    const onErr = ({errors}:any) => setErrors(errors);
    s.on('connect', open); s.on('step:locked', onLocked); s.on('step:unlocked', onUnlocked); s.on('step:updated', onUpdated); s.on('branch:changed', onBranch); s.on('validation:errors', onErr);
    if (s.connected) open();
    return () => { s.off('connect', open); s.off('step:locked', onLocked); s.off('step:unlocked', onUnlocked); s.off('step:updated', onUpdated); s.off('branch:changed', onBranch); s.off('validation:errors', onErr); };
  }, [appId, token]);
  const lock = useCallback((stepId:string) => new Promise<boolean>((res)=>getSock(token).emit('step:lock',{appId,stepId},(r:any)=>res(!!r.ok))), [appId, token]);
  const unlock = useCallback((stepId:string) => getSock(token).emit('step:unlock',{appId,stepId}), [appId, token]);
  const submit = useCallback((stepId:string, fields:any) => new Promise((res,rej) => getSock(token).emit('step:submit',{appId,stepId,fields,expectedVersion:app?.version},(r:any)=>r.error?rej(r):res(r))), [appId, token, app?.version]);
  return { app, locks, errors, lock, unlock, submit };
}

