// src/routes/webhooks.ts
import { Router } from 'express';
import { pool } from '../infra/pg';
import { io } from '../server';
export const webhooksRouter = Router();
const STATE_ORDER = ['placed','paid','packed','shipped','in_transit','delivered','cancelled'];
webhooksRouter.post('/webhooks/:carrier', async (req, res) => {
  const carrier = req.params.carrier;
  const { carrierEventId, trackingId, status, location, ts } = req.body;
  if (!verifyCarrierSig(carrier, req)) return res.status(401).end();
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const ord = await client.query('SELECT id, status FROM orders WHERE carrier_tracking_id=$1 FOR UPDATE', [trackingId]);
    if (!ord.rows[0]) { await client.query('ROLLBACK'); return res.status(404).end(); }
    const inserted = await client.query('INSERT INTO order_events(order_id, status, location, ts, carrier_event_id, carrier) VALUES ($1,$2,$3,to_timestamp($4/1000.0),$5,$6) ON CONFLICT (carrier, carrier_event_id) DO NOTHING RETURNING id', [ord.rows[0].id, status, location, ts, carrierEventId, carrier]);
    if (inserted.rowCount === 0) { await client.query('COMMIT'); return res.json({ ok: true, dedup: true }); }
    // monotonic state update
    const curRank = STATE_ORDER.indexOf(ord.rows[0].status);
    const newRank = STATE_ORDER.indexOf(status);
    if (newRank > curRank) await client.query('UPDATE orders SET status=$1, updated_at=now() WHERE id=$2', [status, ord.rows[0].id]);
    await client.query('COMMIT');
    io.of('/orders').to(`order:${ord.rows[0].id}`).emit('order:event', { orderId: String(ord.rows[0].id), status, location, ts });
    res.json({ ok: true });
  } catch (e) { await client.query('ROLLBACK'); throw e; } finally { client.release(); }
});
function verifyCarrierSig(c:string, req:any){ return true; /* HMAC */ }

