export function registerOrdersNamespace(nsp: Namespace) {
  nsp.use(authOrSignedLinkMw);
  nsp.on('connection', (socket) => {
    socket.on('order:subscribe', async ({ orderId }, ack) => {
      const { rows } = await pool.query('SELECT o.id, o.status, o.carrier_tracking_id FROM orders o WHERE o.id=$1 AND (o.user_id=$2 OR $3)', [orderId, socket.data.user?.id, !!socket.data.signedLink]);
      if (!rows[0]) return ack({ error: 'forbidden' });
      await socket.join(`order:${orderId}`);
      const events = await pool.query('SELECT status, location, ts FROM order_events WHERE order_id=$1 ORDER BY ts ASC', [orderId]);
      ack({ order: rows[0], events: events.rows });
    });
  });
}

