export async function ingestDriverLoc(driverId:string, lat:number, lng:number) {
  await DriverLoc.create({ driverId, ts: new Date(), lat, lng });
  const lastEmit = await redis.get(`drv:emit:${driverId}`);
  if (!lastEmit || Date.now() - Number(lastEmit) > 1000) {
    await redis.set(`drv:emit:${driverId}`, String(Date.now()), 'EX', 5);
    io.of('/orders').to(`driver:${driverId}`).emit('driver:location', { driverId, lat, lng, ts: Date.now() });
  }
}

