import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
function getSock(t:string){ if(sock) return sock; sock = io('/orders',{auth:{token:t},transports:['websocket']}); return sock; }
export function useOrderTracking(orderId:string, token:string) {
  const [order, setOrder] = useState<any>(null);
  const [events, setEvents] = useState<any[]>([]);
  useEffect(() => {
    const s = getSock(token);
    const sub = () => s.emit('order:subscribe',{orderId},(r:any)=>{ if(!r.error){ setOrder(r.order); setEvents(r.events); } });
    const onEvt = (e:any) => { if (e.orderId !== orderId) return; setEvents(p => [...p, e]); setOrder((o:any) => o ? { ...o, status: e.status } : o); };
    s.on('connect', sub); s.on('order:event', onEvt);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('order:event', onEvt); };
  }, [orderId, token]);
  return { order, events };
}

