// src/middleware/tenant.ts
import { Socket } from 'socket.io';
import { pool } from '../infra/pg';
import { redis } from '../infra/redis';
export async function tenantAuthMw(socket: Socket, next: (err?:Error)=>void) {
  try {
    const tok = socket.handshake.auth?.token;
    const claims = await verifyJwt(tok);
    if (!claims.tid) return next(new Error('no_tenant'));
    const { rows } = await pool.query('SELECT id, max_viewers, max_events_per_sec FROM tenants WHERE id=$1', [claims.tid]);
    if (!rows[0]) return next(new Error('tenant_not_found'));
    const viewers = await redis.scard(`tenant:${claims.tid}:viewers`);
    if (viewers >= rows[0].max_viewers) return next(new Error('viewer_cap'));
    (socket.data as any).tenant = rows[0];
    (socket.data as any).user = { id: claims.sub, tenantId: claims.tid };
    await redis.sadd(`tenant:${claims.tid}:viewers`, socket.id);
    socket.on('disconnect', () => redis.srem(`tenant:${claims.tid}:viewers`, socket.id));
    next();
  } catch (e:any) { next(new Error(e.message || 'auth_failed')); }
}

// src/socket/analytics.namespace.ts
import { Namespace } from 'socket.io';
import mongoose from 'mongoose';
import { tenantAuthMw } from '../middleware/tenant';
import { redis } from '../infra/redis';

type CursorEntry = { changeStream: any; refCount: number; idleAt?: number };
const tenantCursors = new Map<string, CursorEntry>();

async function ensureCursor(tenantId: string, nsp: Namespace) {
  let entry = tenantCursors.get(tenantId);
  if (entry) { entry.refCount++; entry.idleAt = undefined; return entry; }
  const coll = mongoose.connection.collection(`tenant_${tenantId}_events`);
  const resume = await redis.get(`tenant:${tenantId}:cursor`);
  const cs = coll.watch([{ $match: { operationType: 'insert' } }], { resumeAfter: resume ? JSON.parse(resume) : undefined });
  entry = { changeStream: cs, refCount: 1 };
  tenantCursors.set(tenantId, entry);
  (async () => {
    try {
      for await (const ch of cs) {
        await redis.set(`tenant:${tenantId}:cursor`, JSON.stringify(ch._id));
        const doc = (ch as any).fullDocument;
        if (!doc) continue;
        // tenant prefix in room ensures no cross-tenant leak even if dashId collides
        nsp.to(`tenant:${tenantId}:dash:${doc.dashId}`).emit('tick', doc);
      }
    } catch (e) { tenantCursors.delete(tenantId); }
  })();
  return entry;
}
async function releaseCursor(tenantId: string) {
  const e = tenantCursors.get(tenantId); if (!e) return;
  e.refCount--;
  if (e.refCount <= 0) { e.idleAt = Date.now(); setTimeout(async () => { if (e.refCount === 0 && Date.now() - (e.idleAt||0) >= 300_000) { try { await e.changeStream.close(); } catch {} tenantCursors.delete(tenantId); } }, 300_000); }
}

export function registerAnalyticsNamespace(nsp: Namespace) {
  nsp.use(tenantAuthMw);
  nsp.on('connection', (socket) => {
    const tenantId = socket.data.user.tenantId;
    let subscribedDash: string | null = null;
    socket.on('dash:subscribe', async ({ dashId }, ack) => {
      // verify dash belongs to tenant
      const dash = await mongoose.connection.collection(`tenant_${tenantId}_dashboards`).findOne({ _id: dashId } as any);
      if (!dash) { await audit(socket.data.user.id, tenantId, 'cross_tenant_dash_attempt', { dashId }); return ack({ error: 'forbidden' }); }
      await socket.join(`tenant:${tenantId}:dash:${dashId}`);
      await ensureCursor(tenantId, nsp);
      subscribedDash = dashId;
      ack({ ok: true });
    });
    socket.on('disconnect', async () => {
      if (subscribedDash) await releaseCursor(tenantId);
    });
  });
}

