// quota for event ingest (HTTP route)
import { Router } from 'express';
import { redis as r } from '../infra/redis';
export const ingestRouter = Router();
ingestRouter.post('/events', async (req, res) => {
  const tid = (req as any).user.tenantId;
  const key = `quota:${tid}:eps:${Math.floor(Date.now()/1000)}`;
  const n = await r.incr(key);
  if (n === 1) await r.expire(key, 2);
  const tenant = await pool.query('SELECT max_events_per_sec FROM tenants WHERE id=$1', [tid]);
  if (n > tenant.rows[0].max_events_per_sec) return res.status(429).json({ error: 'eps_cap' });
  const coll = mongoose.connection.collection(`tenant_${tid}_events`);
  await coll.insertOne({ ...req.body, tenantId: tid, createdAt: new Date() });
  res.json({ ok: true });
});

