// src/socket/analyticsSocket.ts (singleton)
import { io, Socket } from 'socket.io-client';
let sock: Socket | null = null;
export function getAnalyticsSock(token:string){ if(sock) return sock; sock = io('/analytics',{auth:{token},transports:['websocket'],reconnection:true}); return sock; }

// src/hooks/useTenantDashboard.ts
import { useEffect, useState } from 'react';
import { getAnalyticsSock } from '../socket/analyticsSocket';
export function useTenantDashboard(dashId:string, token:string) {
  const [ticks, setTicks] = useState<any[]>([]);
  const [error, setError] = useState<string|null>(null);
  useEffect(() => {
    const s = getAnalyticsSock(token);
    const sub = () => s.emit('dash:subscribe',{dashId},(r:any)=>{ if(r.error) setError(r.error); });
    const onTick = (t:any) => { if (t.dashId !== dashId) return; setTicks(p => [...p.slice(-1000), t]); };
    const onErr = (e:any) => setError(e.message);
    s.on('connect', sub); s.on('tick', onTick); s.on('connect_error', onErr);
    if (s.connected) sub();
    return () => { s.off('connect', sub); s.off('tick', onTick); s.off('connect_error', onErr); };
  }, [dashId, token]);
  return { ticks, error };
}
